 16→import { SECTIONS } from './TopNav';
 17→
 18→// ═══════════════════════════════════════════════════════════
 19→// TYPES
 20→// ═══════════════════════════════════════════════════════════
 21→
 22→interface SidebarItem {
 23→  type: 'link';
 24→  id: string;
 25→  label: string;
 26→  icon: React.ElementType;
 27→  badge?: string;
 28→  badgeColor?: string;
 29→}
 30→
 31→interface SidebarSeparator {
 32→  type: 'separator';
 33→  label: string;
 34→}
 35→
 36→type SidebarEntry = SidebarItem | SidebarSeparator;
 37→
 38→// ═══════════════════════════════════════════════════════════
 39→// MAPPING SECTION → SOUS-ITEMS (SOURCE DE VÉRITÉ)
 40→// ═══════════════════════════════════════════════════════════
 41→
 42→const SIDEBAR_ITEMS: Record<string, SidebarEntry[]> = {
 43→
 44→  // Dashboard — PAS DE SIDEBAR (page pleine largeur)
 45→
 46→  analyse: [
 47→    { type: 'link', id: 'new-analysis',  label: 'Nouvel audit',        icon: PlusCircle },
 48→    { type: 'link', id: 'results',       label: "Résultats d'audit",   icon: BarChart3 },
