 94→  ],
 95→};
 96→
 97→export { SIDEBAR_ITEMS };
 98→
 99→// ═══════════════════════════════════════════════════════════
100→// PAGE ALIASES — pour le highlight du bon item
101→// ═══════════════════════════════════════════════════════════
102→
103→const PAGE_ALIASES: Record<string, string> = {
104→  'analyze': 'new-analysis',
105→  'audit-aeo': 'results',
106→  'alerts': 'alerts-aeo',
107→  'answer-first-audit': 'answer-first',
108→  'api-keys': 'api-developer',
109→  'credits': 'recharge',
110→  'profile': 'account',
111→  'subscription': 'plan',
112→  'publisher-request': 'publisher-search',
113→  'generative-tools': 'smc-studio',
114→  'directory-entity': 'directory',
115→};
116→
117→function resolveActivePage(pageId: string): string {
118→  return PAGE_ALIASES[pageId] || pageId;
119→}
120→
121→// ═══════════════════════════════════════════════════════════
122→// COMPONENT
123→// ═══════════════════════════════════════════════════════════
124→
125→interface SidebarProps {
126→  section: string;
127→  activePage: string;
128→  onPageChange: (page: string) => void;
129→  onSectionChange: (section: string) => void;
130→  credits: number;
131→  plan: string;
132→  onLogoClick?: () => void;
133→}
134→
135→export default function Sidebar({
136→  section,
137→  activePage,
138→  onPageChange,
139→  onSectionChange,
140→  credits,
141→  plan,
142→  onLogoClick,
143→}: SidebarProps) {
144→  const [mobileOpen, setMobileOpen] = useState(false);
145→  const items = SIDEBAR_ITEMS[section];
146→  const resolved = resolveActivePage(activePage);
147→
148→  // ── Render nav items (Raycast style) ──
149→  const renderNavItems = (entries: SidebarEntry[], onClose?: () => void) => (
150→    <nav className="flex-1 overflow-y-auto py-3 px-3">
151→      {entries.map((entry, i) => {
152→        if (entry.type === 'separator') {
153→          return (
154→            <div key={`sep-${i}`} className="text-[11px] font-medium uppercase tracking-wider text-zinc-600 px-3 mt-5 mb-1.5">
155→              {entry.label}
156→            </div>
157→          );
158→        }
159→
160→        const Icon = entry.icon;
161→        const isActive = resolved === entry.id;
162→        return (
163→          <button
164→            key={entry.id}
165→            onClick={() => { onPageChange(entry.id); onClose?.(); }}
166→            className={`group flex items-center gap-2.5 w-full px-2.5 py-[7px] rounded-lg text-[13px] leading-none cursor-pointer transition-all duration-150 relative ${
167→              isActive
168→                ? 'text-white bg-white/[0.08]'
169→                : 'text-zinc-500 hover:text-zinc-300 hover:bg-white/[0.04]'
170→            }`}
171→          >
172→            {isActive && (
173→              <div className="absolute left-0 top-1/2 -translate-y-1/2 w-[2px] h-4 bg-blue-500 rounded-r-full" />
174→            )}
175→            <Icon className={`w-4 h-4 flex-shrink-0 ${
176→              isActive
177→                ? 'text-blue-400'
178→                : 'text-zinc-600 group-hover:text-zinc-400'
179→            }`} />
180→            <span className="truncate">{entry.label}</span>
181→            {entry.badge && (
182→              <span className={`ml-auto text-[10px] font-semibold min-w-[18px] h-[18px] rounded-full flex items-center justify-center px-1 ${
183→                entry.badgeColor === 'red'
184→                  ? 'bg-red-500/15 text-red-400'
185→                  : 'bg-[var(--bg-elevated)] text-[var(--text-tertiary)]'
186→              }`}>
187→                {entry.badge}
188→              </span>
189→            )}
190→          </button>
191→        );
192→      })}
193→    </nav>
194→  );
195→
196→  // ── Credits footer ──
197→  const creditsFooter = (
198→    <div className="border-t border-white/[0.06] p-3 flex-shrink-0 mx-1">
199→      <div className="text-[11px] text-zinc-600 font-medium uppercase tracking-wider">Plan {plan}</div>
200→      <div className="h-1 w-full rounded-full bg-white/[0.06] mt-2 overflow-hidden">
201→        <div
202→          className="h-full bg-blue-500 rounded-full transition-all duration-500"
203→          style={{ width: `${Math.min(100, (credits / 200) * 100)}%` }}
204→        />
205→      </div>
206→      <div className="text-[11px] text-zinc-600 mt-1.5">
207→        <span className="text-zinc-500">{credits}</span> / 200 crédits
208→      </div>
209→    </div>
210→  );
211→
212→  return (
213→    <>
214→      {/* ═══ Desktop sidebar ═══ */}
215→      {items && items.length > 0 && (
216→        <aside className="hidden md:flex flex-col shrink-0 w-60 bg-[#09090B]/90 backdrop-blur-md border-r border-white/[0.06] overflow-y-auto">
217→          {renderNavItems(items)}
218→          {creditsFooter}
219→        </aside>
220→      )}
221→
222→      {/* ═══ Mobile hamburger button ═══ */}
223→      <button
224→        onClick={() => setMobileOpen(!mobileOpen)}
225→        className="md:hidden fixed top-3 left-3 z-[60] p-2 rounded-lg bg-[var(--bg-elevated)]/80 backdrop-blur text-[var(--text-secondary)] hover:text-[var(--text-primary)]"
226→      >
227→        {mobileOpen ? <X size={20} /> : <Menu size={20} />}
228→      </button>
229→
230→      {/* ═══ Mobile overlay ═══ */}
231→      {mobileOpen && (
232→        <>
233→          <div
234→            className="md:hidden fixed inset-0 z-[55] bg-black/60 backdrop-blur-sm"
235→            onClick={() => setMobileOpen(false)}
236→          />
237→          <aside className="md:hidden flex flex-col fixed top-0 left-0 bottom-0 w-72 z-[56] bg-[var(--bg-base)] border-r border-[var(--border-subtle)]">
238→            {/* Logo */}
239→            <div
240→              className="px-5 h-14 flex items-center border-b border-[var(--border-subtle)] flex-shrink-0 cursor-pointer"
