 59→/* ═══════════════════════════════════════════════════════════
 60→   FONDATIONS
 61→   ═══════════════════════════════════════════════════════════ */
 62→
 63→html, body, #root {
 64→  margin: 0;
 65→  padding: 0;
 66→  min-height: 100%;
 67→  background-color: var(--bg-base);
 68→  color: var(--text-primary);
 69→  font-family: 'Geist Sans', 'Inter', system-ui, -apple-system, sans-serif;
 70→  line-height: 1.45;
 71→  -webkit-font-smoothing: antialiased;
 72→  -moz-osx-font-smoothing: grayscale;
 73→  text-rendering: optimizeLegibility;
 74→}
 75→
 76→code, pre, .font-mono, kbd {
 77→  font-family: 'Geist Mono', 'SF Mono', Consolas, monospace;
 78→}
 79→
 80→h1, h2, h3, h4, h5, h6 {
 81→  font-family: 'Geist Sans', 'Inter', system-ui, sans-serif;
 82→  letter-spacing: -0.025em;
 83→}
 84→
 85→/* ═══ SELECTION ═══ */
 86→::selection {
 87→  background-color: var(--accent);
 88→  color: white;
 89→}
 90→
 91→/* ═══════════════════════════════════════════════════════════
 92→   SCROLLBAR (style Linear/Raycast — fine, discrète)
 93→   ═══════════════════════════════════════════════════════════ */
 94→
 95→* {
 96→  scrollbar-width: thin;
 97→  scrollbar-color: var(--border-default) transparent;
 98→}
 99→
100→::-webkit-scrollbar {
101→  width: 6px;
102→  height: 6px;
103→}
104→::-webkit-scrollbar-track {
105→  background: transparent;
106→}
107→::-webkit-scrollbar-thumb {
108→  background: var(--border-default);
109→  border-radius: 3px;
110→}
111→::-webkit-scrollbar-thumb:hover {
112→  background: var(--border-strong);
113→}
114→::-webkit-scrollbar-corner {
115→  background: transparent;
116→}
117→
118→/* Custom scrollbar for modals */
119→.modal-scroll::-webkit-scrollbar {
120→  width: 6px;
121→}
122→.modal-scroll::-webkit-scrollbar-track {
123→  background: var(--bg-surface);
124→  border-radius: 3px;
125→}
126→.modal-scroll::-webkit-scrollbar-thumb {
127→  background: var(--border-strong);
128→  border-radius: 3px;
129→}
130→.modal-scroll::-webkit-scrollbar-thumb:hover {
131→  background: var(--text-disabled);
132→}
133→
134→/* ═══ FOCUS VISIBLE (accessibilité) ═══ */
135→*:focus-visible {
136→  outline: 2px solid var(--accent);
137→  outline-offset: 2px;
138→  border-radius: 4px;
139→}
140→
141→/* ═══════════════════════════════════════════════════════════
142→   ANIMATIONS
143→   ═══════════════════════════════════════════════════════════ */
144→
145→/* Page enter animation */
146→@keyframes fadeInUp {
147→  from {
148→    opacity: 0;
149→    transform: translateY(8px);
150→  }
151→  to {
152→    opacity: 1;
153→    transform: translateY(0);
154→  }
155→}
156→
157→.page-enter {
158→  animation: fadeInUp 0.2s ease-out;
159→}
160→
161→/* Existing animations (preserved) */
162→@keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
163→@keyframes zoom-in { from { transform: scale(0.95); } to { transform: scale(1); } }
164→@keyframes slide-in-from-bottom { from { transform: translateY(8px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
165→@keyframes slide-in-from-right { from { transform: translateX(20px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
166→.animate-in { animation: fade-in 0.5s ease-out, zoom-in 0.3s ease-out; }
167→.animate-slide-up { animation: slide-in-from-bottom 0.3s ease-out; }
168→.animate-slide-right { animation: slide-in-from-right 0.3s ease-out; }
169→
170→/* Shimmer skeleton animation */
171→@keyframes shimmer {
172→  0% { background-position: -200% 0; }
173→  100% { background-position: 200% 0; }
174→}
175→.skeleton-shimmer {
176→  background: linear-gradient(90deg, rgba(255,255,255,0.03) 25%, rgba(255,255,255,0.06) 50%, rgba(255,255,255,0.03) 75%);
177→  background-size: 200% 100%;
178→  animation: shimmer 1.8s ease-in-out infinite;
179→}
180→
181→/* Fade up in */
182→@keyframes fade-up-in { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
183→.animate-fade-up { animation: fade-up-in 0.25s ease-out; }
184→
185→/* ═══ STAGGERED ANIMATIONS (cards, lists) ═══ */
186→.stagger-1 { animation-delay: 50ms; }
187→.stagger-2 { animation-delay: 100ms; }
188→.stagger-3 { animation-delay: 150ms; }
189→.stagger-4 { animation-delay: 200ms; }
190→.stagger-5 { animation-delay: 250ms; }
191→.stagger-6 { animation-delay: 300ms; }
192→
193→/* Slide up for staggered items */
194→@keyframes staggerSlideUp {
195→  from { opacity: 0; transform: translateY(12px); }
196→  to { opacity: 1; transform: translateY(0); }
197→}
198→.stagger-enter {
199→  opacity: 0;
200→  animation: staggerSlideUp 0.3s ease-out forwards;
201→}
202→
203→/* Scale in for modals/tooltips */
204→@keyframes scaleIn {
205→  from { opacity: 0; transform: scale(0.95); }
206→  to { opacity: 1; transform: scale(1); }
207→}
208→.scale-enter {
209→  animation: scaleIn 0.15s ease-out;
210→}
211→
212→/* ═══ MICRO-INTERACTION UTILITIES ═══ */
213→
214→/* Card hover lift effect */
215→.hover-lift {
216→  transition: transform 0.2s ease-out, box-shadow 0.2s ease-out, border-color 0.2s ease-out;
217→}
218→.hover-lift:hover {
219→  transform: translateY(-2px);
220→  box-shadow: 0 8px 25px -5px rgba(0, 0, 0, 0.3);
221→}
222→
223→/* Subtle press effect for buttons */
224→.press-effect:active {
225→  transform: scale(0.98);
226→}
227→
228→/* Glow effect for accent elements */
229→.glow-accent {
230→  transition: box-shadow 0.3s ease-out;
231→}
232→.glow-accent:hover {
233→  box-shadow: 0 0 20px -5px var(--accent);
234→}
235→
236→/* Pulse dot animation (for live indicators) */
237→@keyframes pulseDot {
238→  0%, 100% { opacity: 1; transform: scale(1); }
239→  50% { opacity: 0.5; transform: scale(1.5); }
240→}
241→.pulse-dot {
242→  animation: pulseDot 2s ease-in-out infinite;
243→}
244→
245→/* Spin animation for loaders */
246→@keyframes smoothSpin {
247→  from { transform: rotate(0deg); }
