// components/ui/Card.tsx
// Card subtile — inspirée Linear/Stripe. Pas de shadow, border fine.

import React from 'react';

interface CardProps {
  children: React.ReactNode;
  className?: string;
  hover?: boolean;
  padding?: 'none' | 'sm' | 'md' | 'lg';
}

const PADDING = {
  none: '',
  sm: 'p-4',
  md: 'p-5',
  lg: 'p-6',
};

export default function Card({ children, className = '', hover = false, padding = 'md' }: CardProps) {
  return (
    <div
      className={`
        bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl
        ${PADDING[padding]}
        ${hover ? 'hover:border-[var(--border-strong)] hover:bg-[#1C1C20] cursor-pointer hover-lift' : ''}
        transition-all duration-200
        ${className}
      `.trim()}
    >
      {children}
    </div>
  );
}

