    { url: 'tech-news.io/ai-trends', score: 88, citation: '82%', date: 'Hier', status: 'Excellent', statusClass: 'bg-purple-400/20 text-purple-300' },
    { url: 'startup.co/blog/growth', score: 58, citation: '42%', date: 'Hier', status: 'Moyen', statusClass: 'bg-blue-500/20 text-blue-400' },
    { url: 'ecommerce.shop/products', score: 91, citation: '88%', date: 'Il y a 2 jours', status: 'Excellent', statusClass: 'bg-purple-400/20 text-purple-300' },
  ];

  const tableData: TableRow[] = history.length > 0 ? history.map(h => ({
    url: new URL(h.url).hostname + new URL(h.url).pathname,
    score: h.globalScore,
    citation: `${h.aiCitation.probability}%`,
    date: new Date(h.timestamp).toLocaleDateString(),
    status: h.globalScore >= 80 ? 'Excellent' : h.globalScore >= 60 ? 'Bon' : 'Moyen',
    statusClass: h.globalScore >= 80 ? 'bg-purple-400/20 text-purple-300' : h.globalScore >= 60 ? 'bg-primary/20 text-primary' : 'bg-blue-500/20 text-blue-400',
    original: h
  })) : demoData;

  const chartData = [
    { day: 'Lun', score: 72, citations: 45 },
    { day: 'Mar', score: 75, citations: 52 },
    { day: 'Mer', score: 68, citations: 48 },
    { day: 'Jeu', score: 82, citations: 61 },
    { day: 'Ven', score: 79, citations: 58 },
    { day: 'Sam', score: 85, citations: 64 },
    { day: 'Dim', score: 88, citations: 70 },
  ];

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload?.length) {
      return (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-lg shadow-xl p-3">
          <p className="text-[var(--text-tertiary)] text-[13px] mb-1">{label}</p>
          {payload.map((entry: any, i: number) => (
            <p key={i} className="text-[13px] font-bold" style={{ color: entry.color }}>
              {entry.name === 'score' ? 'Score' : 'Citations'}: {entry.value}{entry.name === 'citations' ? '%' : '/100'}
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  const ActionCard = ({ icon: Icon, label, color, view }: { icon: any, label: string, color: string, view: string }) => (
    <button
      onClick={() => onNavigate(view)}
      className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 flex flex-col items-center justify-center gap-3 transition-all duration-200 hover:border-[var(--border-strong)] hover:bg-[#1C1C20] hover-lift press-effect group w-full cursor-pointer"
    >
      <Icon size={28} className={color} />
      <span className="text-[13px] font-medium text-[var(--text-tertiary)] group-hover:text-[var(--text-primary)]">{label}</span>
    </button>
  );

  return (
    <div className="page-enter">
      <PageHeader title="Dashboard" description="Vue d'ensemble de votre activité AEO" />

      {/* Action Cards Row */}
      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-4 mb-8">
        <ActionCard icon={Fuel} label="Gas Station" color="text-primary" view="recharge" />
        <ActionCard icon={FileText} label="Rapport" color="text-blue-400" view="history" />
        <ActionCard icon={Users} label="Client" color="text-purple-400" view="clients" />
        <ActionCard icon={Share2} label="Affiliation" color="text-pink-400" view="affiliation" />
        <ActionCard icon={MessageSquare} label="Message" color="text-white" view="messages" />
        <ActionCard icon={Bell} label="Alertes" color="text-red-400" view="alerts" />
        <ActionCard icon={ShoppingBag} label="Store" color="text-indigo-400" view="directory" />
        <ActionCard icon={Settings} label="Paramètres" color="text-gray-400" view="account" />
      </div>

      {/* KPI Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4 mb-8">
        {/* Score Moyen */}
        <div className="relative bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 group cursor-default stagger-enter stagger-1" ref={scoreKpi.ref}>
          <p className="text-[13px] text-[var(--text-tertiary)] font-medium tracking-wide uppercase">Score Moyen</p>
          <div className="flex items-baseline mt-2">
            <span className="text-3xl font-semibold text-[var(--text-primary)] tracking-tight">{scoreKpi.count}</span>
            <span className="text-lg text-[var(--text-tertiary)] font-normal ml-0.5">/100</span>
          </div>
          <div className="flex items-center gap-1 mt-2 text-[13px] text-[var(--success)]">
            <TrendingUp className="w-3.5 h-3.5" />
            <span>+5.2% ce mois</span>
          </div>
          <div className="absolute top-5 right-5 w-9 h-9 rounded-lg bg-purple-500/10 flex items-center justify-center">
            <TrendingUp className="w-[18px] h-[18px] text-purple-400" />
          </div>
        </div>

        {/* Taux Citation IA */}
        <div className="relative bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 group cursor-default stagger-enter stagger-2" ref={citationKpi.ref}>
          <p className="text-[13px] text-[var(--text-tertiary)] font-medium tracking-wide uppercase">Taux Citation IA</p>
          <div className="flex items-baseline mt-2">
            <span className="text-3xl font-semibold text-[var(--text-primary)] tracking-tight">{citationKpi.count}</span>
            <span className="text-lg text-[var(--text-tertiary)] font-normal ml-0.5">%</span>
          </div>
          <div className="flex items-center gap-1 mt-2 text-[13px] text-[var(--success)]">
            <TrendingUp className="w-3.5 h-3.5" />
            <span>+12% ce mois</span>
          </div>
          <div className="absolute top-5 right-5 w-9 h-9 rounded-lg bg-emerald-500/10 flex items-center justify-center">
            <Target className="w-[18px] h-[18px] text-emerald-400" />
          </div>
        </div>

        {/* Projets Actifs */}
        <div className="relative bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 group cursor-default stagger-enter stagger-3" ref={projectsKpi.ref}>
          <p className="text-[13px] text-[var(--text-tertiary)] font-medium tracking-wide uppercase">Projets Actifs</p>
          <div className="flex items-baseline mt-2">
            <span className="text-3xl font-semibold text-[var(--text-primary)] tracking-tight">{projectsKpi.count}</span>
          </div>
          <div className="absolute top-5 right-5 w-9 h-9 rounded-lg bg-[var(--accent-subtle)] flex items-center justify-center">
            <BarChart3 className="w-[18px] h-[18px] text-[var(--accent-text)]" />
          </div>
        </div>

        {/* Alertes Actives */}
        <div className="relative bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 group cursor-default stagger-enter stagger-4" ref={alertsKpi.ref}>
          <p className="text-[13px] text-[var(--text-tertiary)] font-medium tracking-wide uppercase">Alertes Actives</p>
          <div className="flex items-baseline mt-2">
            <span className="text-3xl font-semibold text-[var(--text-primary)] tracking-tight">{alertsKpi.count}</span>
          </div>
          <div className="flex items-center gap-1 mt-2 text-[13px] text-[var(--error)]">
            <ArrowDownRight className="w-3.5 h-3.5" />
            <span>1 critique</span>
          </div>
          <div className="absolute top-5 right-5 w-9 h-9 rounded-lg bg-[var(--error-subtle)] flex items-center justify-center">
            <AlertTriangle className="w-[18px] h-[18px] text-[var(--error)]" />
          </div>
        </div>
      </div>

      {/* Main Grid */}
      <div className="grid lg:grid-cols-3 gap-6">

        {/* Table Column (2/3) */}
        <div className="lg:col-span-2 bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-semibold text-[var(--text-primary)] tracking-tight">Dernières analyses</h2>
            <select className="bg-white/[0.06] border border-white/[0.06] text-[var(--text-secondary)] text-[13px] rounded-lg px-3 py-1.5 focus:outline-none focus:border-[var(--accent)]">
              <option>Tous les statuts</option>
              <option>Excellent</option>
              <option>Bon</option>
              <option>Moyen</option>
            </select>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[var(--text-disabled)] text-[13px] border-b border-[var(--border-subtle)]">
                  <th className="pb-3 font-medium pl-2">URL</th>
                  <th className="pb-3 font-medium">Score</th>
                  <th className="pb-3 font-medium">Citation IA</th>
                  <th className="pb-3 font-medium">Date</th>
                  <th className="pb-3 font-medium">Statut</th>
                </tr>
              </thead>
              <tbody className="text-[13px]">
                {tableData.map((row, idx) => (
                  <tr
                    key={idx}
                    className="border-b border-[var(--border-subtle)] last:border-0 hover:bg-white/[0.03]/50 transition-colors cursor-pointer group"
                    onClick={() => row.original ? onView(row.original) : null}
                  >
                    <td className="py-3 pl-2 font-medium text-[var(--text-secondary)] group-hover:text-[var(--text-primary)] transition-colors">{row.url}</td>
                    <td className="py-3">
                      <span className="text-[var(--text-primary)] font-semibold">{row.score}</span>
                      <span className="text-[var(--text-disabled)] text-[12px]">/100</span>
                    </td>
                    <td className="py-3 text-[var(--text-secondary)]">{row.citation}</td>
                    <td className="py-3 text-[var(--text-disabled)]">{row.date}</td>
                    <td className="py-3">
                      <span className={`px-2 py-0.5 rounded-md text-[11px] font-medium ${row.statusClass}`}>
                        {row.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="flex justify-between items-center mt-6 text-[13px] text-[var(--text-disabled)] pt-4 border-t border-[var(--border-subtle)]">
            <div>Affichage 1-5 sur 24 résultats</div>
            <div className="flex items-center gap-1">
              <button className="w-7 h-7 flex items-center justify-center rounded-md bg-white/[0.06] hover:bg-[var(--bg-overlay)] transition-colors text-[var(--text-tertiary)]"><ChevronLeft size={14} /></button>
              <button className="w-7 h-7 flex items-center justify-center rounded-md bg-[var(--accent)] text-white text-[13px] font-medium">1</button>
              <button className="w-7 h-7 flex items-center justify-center rounded-md bg-white/[0.06] hover:bg-[var(--bg-overlay)] transition-colors text-[var(--text-tertiary)] text-[13px]">2</button>
              <button className="w-7 h-7 flex items-center justify-center rounded-md bg-white/[0.06] hover:bg-[var(--bg-overlay)] transition-colors text-[var(--text-tertiary)] text-[13px]">3</button>
              <button className="w-7 h-7 flex items-center justify-center rounded-md bg-white/[0.06] hover:bg-[var(--bg-overlay)] transition-colors text-[var(--text-tertiary)]"><ChevronRight size={14} /></button>
            </div>
          </div>
        </div>

        {/* Chart Column (1/3) */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 h-full min-h-[300px] flex flex-col">
            <h2 className="text-lg font-semibold text-[var(--text-primary)] tracking-tight mb-6">Évolution des scores</h2>

            <div className="flex-1 w-full min-h-[220px]">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData} margin={{ top: 5, right: 5, left: -20, bottom: 0 }}>
                  <defs>
                    <linearGradient id="gradientScore" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#3B82F6" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#3B82F6" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="gradientCitations" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#8B5CF6" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#8B5CF6" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <XAxis
                    dataKey="day"
                    axisLine={false}
                    tickLine={false}
                    tick={{ fill: '#52525B', fontSize: 12 }}
                  />
                  <YAxis
                    axisLine={false}
                    tickLine={false}
                    tick={{ fill: '#52525B', fontSize: 12 }}
                    domain={[0, 100]}
                  />
                  <Tooltip content={<CustomTooltip />} />
                  <Area
                    type="monotone"
                    dataKey="score"
                    stroke="#3B82F6"
                    strokeWidth={2}
                    fill="url(#gradientScore)"
                    name="score"
                  />
                  <Area
                    type="monotone"
                    dataKey="citations"
                    stroke="#8B5CF6"
                    strokeWidth={2}
                    fill="url(#gradientCitations)"
                    name="citations"
                  />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

export default Dashboard;

