// components/ui/Card.tsx
// Card subtile — inspirée Linear/Stripe. Pas de shadow, border fine.

import React from 'react';

interface CardProps {
  children: React.ReactNode;
  className?: string;
  hover?: boolean;
  padding?: 'none' | 'sm' | 'md' | 'lg';
}

const PADDING = {
  none: '',
  sm: 'p-4',
  md: 'p-5',
  lg: 'p-6',
};

export default function Card({ children, className = '', hover = false, padding = 'md' }: CardProps) {
  return (
    <div
      className={`
        bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl
        ${PADDING[padding]}
        ${hover ? 'hover:border-[var(--border-strong)] hover:bg-[#1C1C20] cursor-pointer hover-lift' : ''}
        transition-all duration-200
        ${className}
      `.trim()}
    >
      {children}
    </div>
  );
}

// components/ui/Badge.tsx
// Badge sémantique — statuts, tags, labels.

import React from 'react';

interface BadgeProps {
  children: React.ReactNode;
  variant?: 'default' | 'success' | 'warning' | 'error' | 'blue' | 'purple';
  className?: string;
}

const VARIANT_STYLES = {
  default: 'bg-[var(--bg-elevated)] text-[var(--text-secondary)] border border-[var(--border-default)]',
  success: 'bg-[var(--success-subtle)] text-[var(--success)] border border-green-500/20',
  warning: 'bg-[var(--warning-subtle)] text-[var(--warning)] border border-amber-500/20',
  error: 'bg-[var(--error-subtle)] text-[var(--error)] border border-red-500/20',
  blue: 'bg-[var(--accent-subtle)] text-[var(--accent-text)] border border-blue-500/20',
  purple: 'bg-purple-500/10 text-purple-400 border border-purple-500/20',
};

export default function Badge({ children, variant = 'default', className = '' }: BadgeProps) {
  return (
    <span className={`text-[11px] font-medium px-2 py-0.5 rounded-md inline-flex items-center ${VARIANT_STYLES[variant]} ${className}`}>
      {children}
    </span>
  );
}

// components/ui/Button.tsx
// Système de boutons unifié — Primary inspiré Vercel (blanc sur sombre).

import React from 'react';

interface ButtonProps {
  children: React.ReactNode;
  variant?: 'primary' | 'secondary' | 'ghost' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  icon?: React.ElementType;
  iconPosition?: 'left' | 'right';
  loading?: boolean;
  disabled?: boolean;
  onClick?: () => void;
  className?: string;
  type?: 'button' | 'submit' | 'reset';
}

const VARIANT_STYLES = {
  primary: 'bg-white text-black font-medium hover:bg-gray-200 active:bg-gray-300 disabled:opacity-50',
  secondary: 'bg-transparent text-[var(--text-secondary)] border border-[var(--border-default)] hover:border-[var(--border-strong)] hover:text-[var(--text-primary)]',
  ghost: 'bg-transparent text-[var(--text-secondary)] hover:bg-[var(--bg-elevated)] hover:text-[var(--text-primary)]',
  danger: 'bg-transparent text-[var(--error)] border border-red-500/20 hover:bg-[var(--error-subtle)]',
};

const SIZE_STYLES = {
  sm: 'text-[13px] px-3 py-1.5 rounded-lg gap-1.5',
  md: 'text-sm px-4 py-2 rounded-lg gap-2',
  lg: 'text-sm px-5 py-2.5 rounded-lg gap-2',
};

const Spinner = () => (
  <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" />
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
  </svg>
);

export default function Button({
  children,
  variant = 'primary',
  size = 'md',
  icon: Icon,
  iconPosition = 'left',
  loading = false,
  disabled = false,
  onClick,
  className = '',
  type = 'button',
}: ButtonProps) {
  const isDisabled = disabled || loading;

  return (
    <button
      type={type}
      onClick={onClick}
      disabled={isDisabled}
      className={`
        inline-flex items-center justify-center font-medium
        transition-all duration-150 press-effect
        ${isDisabled ? 'cursor-not-allowed' : 'cursor-pointer'}
        ${VARIANT_STYLES[variant]}
        ${SIZE_STYLES[size]}
        ${className}
      `.trim()}
    >
      {loading && <Spinner />}
      {!loading && Icon && iconPosition === 'left' && <Icon className="w-4 h-4" />}
      <span className={loading ? 'opacity-70' : ''}>{children}</span>
      {!loading && Icon && iconPosition === 'right' && <Icon className="w-4 h-4" />}
    </button>
  );
}

// components/ui/Skeleton.tsx
// Barres de chargement animées — style Linear.
// Utilise shimmer pour un effet de scan lumineux subtil.

import React from 'react';

interface SkeletonProps {
  variant?: 'text' | 'card' | 'circle' | 'title' | 'avatar';
  className?: string;
  width?: string;
  height?: string;
  shimmer?: boolean;
}

const VARIANT_DEFAULTS = {
  text: 'h-4 w-48 rounded',
  title: 'h-6 w-64 rounded',
  card: 'h-32 w-full rounded-xl',
  circle: 'w-10 h-10 rounded-full',
  avatar: 'w-8 h-8 rounded-full',
};

export default function Skeleton({
  variant = 'text',
  className = '',
  width,
  height,
  shimmer = true,
}: SkeletonProps) {
  return (
    <div
      className={`${shimmer ? 'skeleton-shimmer' : 'bg-[var(--bg-elevated)] animate-pulse'} ${VARIANT_DEFAULTS[variant]} ${className}`}
      style={{ ...(width && { width }), ...(height && { height }) }}
      role="status"
      aria-label="Loading..."
    />
  );
}

/** Group of skeleton lines — useful for loading text blocks */
export function SkeletonGroup({
  count = 3,
  variant = 'text',
  gap = 3,
}: {
  count?: number;
  variant?: 'text' | 'card' | 'circle' | 'title' | 'avatar';
  gap?: number;
}) {
  return (
    <div className={`space-y-${gap}`} role="status" aria-label="Loading content...">
      {Array.from({ length: count }).map((_, i) => (
        <Skeleton
          key={i}
          variant={variant}
          className={i === count - 1 && variant === 'text' ? 'w-32' : ''}
        />
      ))}
    </div>
  );
}

/** Card skeleton — mimics a KPI or content card */
export function SkeletonCard() {
  return (
    <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-5 space-y-3">
      <Skeleton variant="text" className="w-24" />
      <Skeleton variant="title" className="w-16" />
      <Skeleton variant="text" className="w-32" />
    </div>
  );
}

