// components/ScoreProjection.tsx
// Real-time before/after AEO score projection panel
// Recalculates projected scores when solutions are toggled

import React, { useMemo } from 'react';
import { CategoryScore, Recommendation } from '../types';
import { BarChart3, TrendingUp, Sparkles } from 'lucide-react';

// ═══════════════════════════════════════════════════════════
// ENGINE TYPES & CATEGORY-LEVEL BIASES
// ═══════════════════════════════════════════════════════════

type EngineId = 'chatgpt' | 'perplexity' | 'gemini';

// Category-level engine biases — derived from averaging
// the 50 per-criterion weights in config/engine-weights.ts
// by their closest category grouping.
const CATEGORY_ENGINE_BIAS: Record<string, Record<EngineId, number>> = {
  technical:       { chatgpt: 0.7, perplexity: 1.0, gemini: 1.1 },
  semantic:        { chatgpt: 1.4, perplexity: 1.4, gemini: 1.3 },
  content:         { chatgpt: 1.3, perplexity: 1.3, gemini: 1.1 },
  entity:          { chatgpt: 0.9, perplexity: 1.3, gemini: 1.1 },
  structured_data: { chatgpt: 0.7, perplexity: 1.2, gemini: 1.3 },
  geo:             { chatgpt: 1.4, perplexity: 1.4, gemini: 1.2 },
  trust:           { chatgpt: 0.8, perplexity: 1.1, gemini: 1.0 },
  freshness:       { chatgpt: 1.1, perplexity: 1.6, gemini: 1.3 },
  media:           { chatgpt: 0.9, perplexity: 1.0, gemini: 1.3 },
  ux:              { chatgpt: 0.5, perplexity: 0.8, gemini: 0.9 },
};

// Engine display info
const ENGINES: Array<{ id: EngineId; label: string; color: string; bgFaded: string }> = [
  { id: 'chatgpt',    label: 'ChatGPT',    color: 'bg-emerald-500', bgFaded: 'bg-emerald-500/30' },
  { id: 'perplexity', label: 'Perplexity', color: 'bg-blue-500',    bgFaded: 'bg-blue-500/30' },
  { id: 'gemini',     label: 'Gemini',      color: 'bg-purple-500',  bgFaded: 'bg-purple-500/30' },
];

// ═══════════════════════════════════════════════════════════
// CITATION RATE ESTIMATION
// ═══════════════════════════════════════════════════════════

function estimateCitationRate(aeoScore: number): number {
  if (aeoScore <= 30) return Math.round(aeoScore * 0.3);
  if (aeoScore <= 50) return Math.round(10 + (aeoScore - 30) * 0.8);
  if (aeoScore <= 70) return Math.round(26 + (aeoScore - 50) * 1.2);
  if (aeoScore <= 85) return Math.round(50 + (aeoScore - 70) * 1.5);
  return Math.round(73 + (aeoScore - 85) * 1.8);
}

// ═══════════════════════════════════════════════════════════
// PROPS
// ═══════════════════════════════════════════════════════════

interface ScoreProjectionProps {
  categories: Record<string, CategoryScore>;
  recommendations: Recommendation[];
  selectedSolutions: Set<string>;
  globalScore: number;
}

// ═══════════════════════════════════════════════════════════
// PROJECTION CALCULATION
// ═══════════════════════════════════════════════════════════

function calculateProjection(
  categories: Record<string, CategoryScore>,
  recommendations: Recommendation[],
  selectedSolutions: Set<string>,
  globalScore: number,
) {
  // Build reverse map: category display name → category ID
  const reverseCategoryMap: Record<string, string> = {};
  for (const [catId, cat] of Object.entries(categories)) {
    reverseCategoryMap[cat.name] = catId;
  }

  // Count how many selected recommendations per category
  const fixedPerCategory: Record<string, number> = {};
  for (const rec of recommendations) {
    if (selectedSolutions.has(rec.id)) {
      const catId = reverseCategoryMap[rec.category];
      if (catId) {
        fixedPerCategory[catId] = (fixedPerCategory[catId] || 0) + 1;
      }
    }
  }

  // Calculate projected category scores
  const projectedCategoryScores: Record<string, number> = {};
  for (const [catId, cat] of Object.entries(categories)) {
    const totalCriteria = cat.items.length;
    const passedCount = cat.items.filter(i => i.status === 'success').length;
    const failedCount = totalCriteria - passedCount;
    // Can't fix more than what's actually failed
    const fixed = Math.min(fixedPerCategory[catId] || 0, failedCount);
    const newPassed = passedCount + fixed;
    projectedCategoryScores[catId] = Math.round((newPassed / totalCriteria) * 100);
  }

  // Projected global score = average of all category scores
  const catIds = Object.keys(categories);
  const projectedGlobalScore = catIds.length > 0
    ? Math.round(catIds.reduce((sum, id) => sum + projectedCategoryScores[id], 0) / catIds.length)
    : globalScore;

  // Engine scores — weighted average of category scores
  const currentEngineScores: Record<EngineId, number> = { chatgpt: 0, perplexity: 0, gemini: 0 };
  const projectedEngineScores: Record<EngineId, number> = { chatgpt: 0, perplexity: 0, gemini: 0 };

  for (const engine of ['chatgpt', 'perplexity', 'gemini'] as EngineId[]) {
    let currentWeightedSum = 0;
    let projectedWeightedSum = 0;
    let totalWeight = 0;

    for (const [catId, cat] of Object.entries(categories)) {
      const bias = CATEGORY_ENGINE_BIAS[catId]?.[engine] ?? 1.0;
      currentWeightedSum += cat.score * bias;
      projectedWeightedSum += projectedCategoryScores[catId] * bias;
      totalWeight += bias;
    }

    currentEngineScores[engine] = totalWeight > 0
      ? Math.round(currentWeightedSum / totalWeight)
      : globalScore;
    projectedEngineScores[engine] = totalWeight > 0
      ? Math.round(projectedWeightedSum / totalWeight)
      : projectedGlobalScore;
  }

  // Citation rates
  const currentCitationRate = estimateCitationRate(globalScore);
  const projectedCitationRate = estimateCitationRate(projectedGlobalScore);

  return {
    projectedGlobalScore,
    globalScoreGain: projectedGlobalScore - globalScore,
    currentEngineScores,
    projectedEngineScores,
    currentCitationRate,
    projectedCitationRate,
    citationRateGain: projectedCitationRate - currentCitationRate,
    selectedCount: selectedSolutions.size,
    totalCount: recommendations.length,
  };
}

// ═══════════════════════════════════════════════════════════
// COMPONENT
// ═══════════════════════════════════════════════════════════

export default function ScoreProjection({
  categories,
  recommendations,
  selectedSolutions,
  globalScore,
}: ScoreProjectionProps) {
  const projection = useMemo(
    () => calculateProjection(categories, recommendations, selectedSolutions, globalScore),
    [categories, recommendations, selectedSolutions, globalScore],
  );

  const {
    projectedGlobalScore,
    globalScoreGain,
    currentEngineScores,
    projectedEngineScores,
    currentCitationRate,
    projectedCitationRate,
    citationRateGain,
    selectedCount,
    totalCount,
  } = projection;

  const hasSelection = selectedCount > 0;

  return (
    <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl overflow-hidden mb-8">

      {/* ── Header ── */}
      <div className="px-6 py-4 border-b border-[var(--border-subtle)] flex justify-between items-center">
        <h3 className="text-[var(--text-primary)] font-semibold flex items-center gap-2">
          <BarChart3 size={18} className="text-[var(--accent-text)]" />
          Impact projeté
        </h3>
        <span className="text-[13px] text-[var(--text-tertiary)]">
          {selectedCount} / {totalCount} solutions sélectionnées
        </span>
      </div>

      {/* ── Score Avant / Après ── */}
      <div className="grid grid-cols-1 sm:grid-cols-2 divide-y sm:divide-y-0 sm:divide-x divide-[var(--border-subtle)]">
        {/* Current */}
        <div className="p-6 text-center">
          <p className="text-[11px] uppercase tracking-wider text-[var(--text-disabled)] mb-3 font-medium">Score actuel</p>
          <div className="flex items-baseline justify-center gap-1">
            <span className="text-5xl font-bold text-[var(--text-primary)] tracking-tight transition-all duration-300">{globalScore}</span>
            <span className="text-lg text-[var(--text-tertiary)]">/100</span>
          </div>
          <div className="mt-4 h-2 rounded-full bg-[var(--bg-elevated)] overflow-hidden">
            <div
              className="h-full bg-[var(--text-disabled)] rounded-full transition-all duration-300"
              style={{ width: `${globalScore}%` }}
            />
          </div>
        </div>

        {/* Projected */}
        <div className="p-6 text-center">
          <p className="text-[11px] uppercase tracking-wider text-[var(--text-disabled)] mb-3 font-medium">Score projeté</p>
          <div className="flex items-baseline justify-center gap-1">
            <span className="text-5xl font-bold text-[var(--accent-text)] tracking-tight transition-all duration-300">
              {projectedGlobalScore}
            </span>
            <span className="text-lg text-[var(--text-tertiary)]">/100</span>
            {globalScoreGain > 0 && (
              <span className="text-[13px] text-[var(--success)] font-medium ml-2 transition-all duration-300">
                +{globalScoreGain}
              </span>
            )}
          </div>
          <div className="mt-4 h-2 rounded-full bg-[var(--bg-elevated)] overflow-hidden">
            <div
              className="h-full bg-[var(--accent)] rounded-full transition-all duration-300"
              style={{ width: `${projectedGlobalScore}%` }}
            />
          </div>
        </div>
      </div>

      {/* ── Scores par moteur IA ── */}
      <div className="px-6 py-4 border-t border-[var(--border-subtle)]">
        <p className="text-[11px] uppercase tracking-wider text-[var(--text-disabled)] mb-3 font-medium">Par moteur IA</p>
        <div className="space-y-3">
          {ENGINES.map(engine => {
            const current = currentEngineScores[engine.id];
            const projected = projectedEngineScores[engine.id];
            const gain = projected - current;

            return (
              <div key={engine.id} className="flex items-center gap-3">
                <span className="w-24 text-[13px] text-[var(--text-tertiary)] truncate">{engine.label}</span>
                <span className="w-16 text-[13px] text-[var(--text-secondary)] text-right tabular-nums">
                  {current}
                  <span className="text-[var(--text-disabled)] mx-1">→</span>
                  <span className="text-[var(--text-primary)]">{projected}</span>
                </span>

                {/* Bar */}
                <div className="flex-1 h-1.5 rounded-full bg-[var(--bg-elevated)] relative overflow-hidden">
                  <div
                    className={`absolute inset-y-0 left-0 rounded-full ${engine.bgFaded} transition-all duration-300`}
                    style={{ width: `${projected}%` }}
                  />
                  <div
                    className={`absolute inset-y-0 left-0 rounded-full ${engine.color} transition-all duration-300`}
                    style={{ width: `${current}%` }}
                  />
                </div>

                <span className={`w-14 text-[13px] text-right tabular-nums transition-all duration-300 ${gain > 0 ? 'text-[var(--success)]' : 'text-[var(--text-disabled)]'}`}>
                  {gain > 0 ? `+${gain}` : '—'}
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* ── Taux de citation estimé ── */}
      <div className="px-6 py-4 border-t border-[var(--border-subtle)]">
        <div className="flex items-center justify-between mb-3">
          <p className="text-[11px] uppercase tracking-wider text-[var(--text-disabled)] flex items-center gap-1.5 font-medium">
            <Sparkles size={12} className="text-[var(--accent-text)]" />
            Taux de citation estimé
          </p>
          {citationRateGain > 0 && (
            <span className="text-[13px] text-[var(--success)] font-semibold flex items-center gap-1 transition-all duration-300">
              <TrendingUp size={14} />
              +{citationRateGain}%
            </span>
          )}
        </div>

        <div className="flex items-center gap-3">
          <span className="text-[13px] text-[var(--text-secondary)] tabular-nums">~{currentCitationRate}%</span>
          <span className="text-[var(--text-disabled)]">→</span>
          <span className={`text-[13px] font-semibold tabular-nums transition-all duration-300 ${hasSelection ? 'text-[var(--accent-text)]' : 'text-[var(--text-primary)]'}`}>
            ~{projectedCitationRate}%
          </span>
        </div>

        <div className="mt-2 h-1.5 rounded-full bg-[var(--bg-elevated)] relative overflow-hidden">
          <div
            className="absolute inset-y-0 left-0 rounded-full bg-[var(--accent)]/30 transition-all duration-300"
            style={{ width: `${projectedCitationRate}%` }}
          />
          <div
            className="absolute inset-y-0 left-0 rounded-full bg-[var(--text-disabled)] transition-all duration-300"
            style={{ width: `${currentCitationRate}%` }}
          />
        </div>
        <div className="flex justify-between mt-1 text-[10px] text-[var(--text-disabled)]">
          <span>0%</span>
          <span>100%</span>
        </div>
      </div>

      {/* ── Footer hint ── */}
      {!hasSelection && (
        <div className="px-6 py-3 border-t border-[var(--border-subtle)] bg-[var(--bg-base)]">
          <p className="text-[12px] text-[var(--text-disabled)] text-center">
            Cochez les solutions ci-dessous pour voir l'impact en temps réel
          </p>
        </div>
      )}
    </div>
  );
}

