238→## ÉTAPE 2 — Créer `services/v3/multilingual-checker.ts`
239→
240→L'orchestrateur qui lance les checks dans chaque langue.
241→
242→```typescript
243→// services/v3/multilingual-checker.ts
244→//
245→// Orchestre l'analyse de citations multilingue.
246→// Pour chaque langue sélectionnée :
247→//   1. Génère les 5 requêtes dans cette langue
248→//   2. Interroge les 3 moteurs IA
249→//   3. Analyse les réponses (citation détectée ou non)
250→//   4. Calcule le taux de citation par langue × moteur
251→//
252→// Utilise le proxy sécurisé (lib/ai-proxy.ts) pour tous les appels.
253→
254→import { callChatGPT, callPerplexity, callGemini } from '../../lib/ai-proxy';
255→import { MULTILINGUAL_QUERY_TEMPLATES, buildQuery, type LanguageCode } from './language-query-templates';
256→// Réutiliser le détecteur de citations existant
257→import { detectCitation } from './citation-detector';
258→
259→// ═══ TYPES ═══
260→
261→export interface MultilingualConfig {
262→  url: string;
263→  brand: string;
264→  industry: string;
265→  useCase?: string;
266→  languages: LanguageCode[];   // Langues à analyser
267→}
268→
269→export interface LanguageCitationResult {
270→  language: LanguageCode;
271→  engine: 'chatgpt' | 'perplexity' | 'gemini';
272→  query: string;
273→  queryId: string;
274→  category: string;
275→  response: string;
276→  cited: boolean;
277→  citationType: 'url' | 'brand' | 'product' | 'none';
278→  position: 'first' | 'mentioned' | 'absent';
279→  sentiment: 'positive' | 'neutral' | 'negative' | 'absent';
280→  competitorsCited: string[];
281→}
282→
283→export interface LanguageSummary {
284→  language: LanguageCode;
285→  totalQueries: number;
286→  citationsByEngine: {
287→    chatgpt: { cited: number; total: number; rate: number };
288→    perplexity: { cited: number; total: number; rate: number };
289→    gemini: { cited: number; total: number; rate: number };
290→  };
291→  overallRate: number;         // 0-100, taux de citation moyen toutes moteurs
292→  topCompetitors: string[];    // Concurrents les plus cités dans cette langue
293→  bestCategory: string;        // Catégorie où on est le plus cité
294→  worstCategory: string;       // Catégorie où on est le moins cité
295→}
296→
297→export interface MultilingualReport {
298→  config: MultilingualConfig;
299→  timestamp: string;
300→  results: LanguageCitationResult[];
301→  summaryByLanguage: LanguageSummary[];
302→  opportunities: Opportunity[];
303→  globalStats: {
304→    bestLanguage: { code: LanguageCode; rate: number };
305→    worstLanguage: { code: LanguageCode; rate: number };
306→    averageRate: number;
307→    totalQueriesRun: number;
308→    totalCitations: number;
309→  };
310→}
311→
312→export interface Opportunity {
313→  type: 'language_gap' | 'engine_gap' | 'category_gap' | 'competitor_threat';
314→  severity: 'high' | 'medium' | 'low';
315→  language: LanguageCode;
316→  engine?: string;
317→  title: string;
318→  description: string;
319→  action: string;
320→  estimatedImpact: string;    // ex: "+40% de reach potentiel"
321→}
322→
323→// ═══ ORCHESTRATEUR PRINCIPAL ═══
324→
325→export async function runMultilingualCheck(
326→  config: MultilingualConfig,
327→  onProgress?: (progress: { 
328→    current: number; 
329→    total: number; 
330→    language: string; 
331→    engine: string;
332→    status: string;
333→  }) => void
334→): Promise<MultilingualReport> {
335→
336→  const results: LanguageCitationResult[] = [];
337→  const engines = ['chatgpt', 'perplexity', 'gemini'] as const;
338→  
339→  const totalSteps = config.languages.length * MULTILINGUAL_QUERY_TEMPLATES.length * engines.length;
340→  let currentStep = 0;
341→
342→  // Pour chaque langue
343→  for (const lang of config.languages) {
344→    // Pour chaque template de requête
345→    for (const template of MULTILINGUAL_QUERY_TEMPLATES) {
346→      // Construire la requête dans cette langue
347→      const queryText = template.template[lang];
348→      if (!queryText) continue;
349→
350→      const query = buildQuery(queryText, {
351→        brand: config.brand,
352→        industry: config.industry,
353→        useCase: config.useCase,
354→      });
355→
356→      // Pour chaque moteur IA
357→      for (const engine of engines) {
358→        currentStep++;
359→        
360→        onProgress?.({
361→          current: currentStep,
362→          total: totalSteps,
363→          language: lang,
364→          engine,
365→          status: `Interrogation ${engine} en ${lang}...`,
366→        });
367→
368→        try {
369→          // Rate limiting entre les appels
370→          const delay = engine === 'perplexity' ? 500 : engine === 'chatgpt' ? 200 : 100;
371→          await new Promise(r => setTimeout(r, delay));
372→
373→          // Appeler le moteur via le proxy sécurisé
374→          let response: string;
375→          switch (engine) {
376→            case 'chatgpt':
377→              response = await callChatGPT(query);
378→              break;
379→            case 'perplexity':
380→              response = await callPerplexity(query);
381→              break;
382→            case 'gemini':
383→              response = await callGemini(query);
384→              break;
385→          }
386→
387→          // Analyser la citation dans la réponse
388→          const citation = detectCitation(response, {
389→            url: config.url,
390→            brand: config.brand,
391→          });
392→
393→          results.push({
394→            language: lang,
395→            engine,
396→            query,
397→            queryId: template.id,
398→            category: template.category,
399→            response,
400→            cited: citation.found,
401→            citationType: citation.type || 'none',
402→            position: citation.position || 'absent',
403→            sentiment: citation.sentiment || 'absent',
404→            competitorsCited: citation.competitors || [],
405→          });
406→
407→        } catch (error) {
408→          // En cas d'erreur, enregistrer comme non-cité
409→          results.push({
410→            language: lang,
411→            engine,
412→            query,
413→            queryId: template.id,
414→            category: template.category,
415→            response: `[Error: ${error instanceof Error ? error.message : 'Unknown'}]`,
416→            cited: false,
417→            citationType: 'none',
418→            position: 'absent',
419→            sentiment: 'absent',
420→            competitorsCited: [],
421→          });
422→        }
423→      }
424→    }
425→  }
426→
427→  // ═══ AGRÉGATION ═══
428→
429→  const summaryByLanguage = aggregateByLanguage(results, config.languages);
430→  const opportunities = identifyOpportunities(summaryByLanguage, config);
431→  const globalStats = computeGlobalStats(summaryByLanguage);
432→
433→  return {
434→    config,
435→    timestamp: new Date().toISOString(),
436→    results,
437→    summaryByLanguage,
438→    opportunities,
439→    globalStats,
440→  };
441→}
442→
443→// ═══ AGRÉGATION PAR LANGUE ═══
444→
445→function aggregateByLanguage(
446→  results: LanguageCitationResult[],
447→  languages: LanguageCode[]
448→): LanguageSummary[] {
449→  return languages.map(lang => {
450→    const langResults = results.filter(r => r.language === lang);
451→    const engines = ['chatgpt', 'perplexity', 'gemini'] as const;
452→
453→    const citationsByEngine = {} as LanguageSummary['citationsByEngine'];
454→    
455→    for (const engine of engines) {
456→      const engineResults = langResults.filter(r => r.engine === engine);
457→      const cited = engineResults.filter(r => r.cited).length;
458→      const total = engineResults.length;
459→      citationsByEngine[engine] = {
460→        cited,
461→        total,
462→        rate: total > 0 ? Math.round((cited / total) * 100) : 0,
463→      };
464→    }
465→
466→    // Taux global
467→    const totalCited = langResults.filter(r => r.cited).length;
468→    const totalQueries = langResults.length;
469→    const overallRate = totalQueries > 0 ? Math.round((totalCited / totalQueries) * 100) : 0;
470→
471→    // Concurrents les plus cités
472→    const competitorCounts: Record<string, number> = {};
473→    for (const r of langResults) {
474→      for (const comp of r.competitorsCited) {
475→        competitorCounts[comp] = (competitorCounts[comp] || 0) + 1;
476→      }
477→    }
478→    const topCompetitors = Object.entries(competitorCounts)
479→      .sort((a, b) => b[1] - a[1])
480→      .slice(0, 5)
481→      .map(([name]) => name);
482→
483→    // Meilleure et pire catégorie
484→    const categories = ['informational', 'comparative', 'transactional', 'reputation'];
485→    const categoryRates = categories.map(cat => {
486→      const catResults = langResults.filter(r => r.category === cat);
487→      const catCited = catResults.filter(r => r.cited).length;
488→      return { category: cat, rate: catResults.length > 0 ? catCited / catResults.length : 0 };
489→    });
490→    categoryRates.sort((a, b) => b.rate - a.rate);
491→
492→    return {
493→      language: lang,
494→      totalQueries,
495→      citationsByEngine,
496→      overallRate,
497→      topCompetitors,
498→      bestCategory: categoryRates[0]?.category || 'N/A',
499→      worstCategory: categoryRates[categoryRates.length - 1]?.category || 'N/A',
500→    };
501→  });
502→}
503→
504→// ═══ IDENTIFICATION DES OPPORTUNITÉS ═══
505→
506→function identifyOpportunities(
507→  summaries: LanguageSummary[],
508→  config: MultilingualConfig
509→): Opportunity[] {
510→  const opportunities: Opportunity[] = [];
511→  
512→  if (summaries.length < 2) return opportunities;
513→
514→  // Trier par taux de citation
515→  const sorted = [...summaries].sort((a, b) => b.overallRate - a.overallRate);
516→  const bestLang = sorted[0];
517→  const worstLang = sorted[sorted.length - 1];
518→
519→  // OPPORTUNITÉ 1 : Gap entre meilleure et pire langue
520→  if (bestLang && worstLang && bestLang.overallRate - worstLang.overallRate > 20) {
521→    const langLabel = SUPPORTED_LANGUAGES_MAP[worstLang.language] || worstLang.language;
522→    const bestLabel = SUPPORTED_LANGUAGES_MAP[bestLang.language] || bestLang.language;
523→    
524→    opportunities.push({
525→      type: 'language_gap',
526→      severity: bestLang.overallRate - worstLang.overallRate > 40 ? 'high' : 'medium',
527→      language: worstLang.language,
528→      title: `Invisible en ${langLabel}`,
529→      description: `Vous êtes cité à ${bestLang.overallRate}% en ${bestLabel} mais seulement ${worstLang.overallRate}% en ${langLabel}. C'est un marché entier que vous ne captez pas.`,
530→      action: `Créer du contenu optimisé AEO en ${langLabel} : FAQ, Schema.org multilingue, page answer-first dédiée.`,
531→      estimatedImpact: `+${Math.round((bestLang.overallRate - worstLang.overallRate) * 0.6)}% de citations potentielles en ${langLabel}`,
532→    });
533→  }
534→
535→  // OPPORTUNITÉ 2 : Gap par moteur dans une langue
536→  for (const summary of summaries) {
537→    const engines = ['chatgpt', 'perplexity', 'gemini'] as const;
538→    const rates = engines.map(e => ({ engine: e, rate: summary.citationsByEngine[e].rate }));
539→    rates.sort((a, b) => b.rate - a.rate);
540→    
541→    if (rates[0].rate - rates[rates.length - 1].rate > 30) {
542→      const langLabel = SUPPORTED_LANGUAGES_MAP[summary.language] || summary.language;
543→      opportunities.push({
544→        type: 'engine_gap',
545→        severity: 'medium',
546→        language: summary.language,
547→        engine: rates[rates.length - 1].engine,
548→        title: `${rates[rates.length - 1].engine} ne vous cite pas en ${langLabel}`,
549→        description: `En ${langLabel}, ${rates[0].engine} vous cite à ${rates[0].rate}% mais ${rates[rates.length - 1].engine} seulement à ${rates[rates.length - 1].rate}%.`,
550→        action: `Optimiser le contenu ${langLabel} selon les critères spécifiques de ${rates[rates.length - 1].engine}.`,
551→        estimatedImpact: `+${Math.round((rates[0].rate - rates[rates.length - 1].rate) * 0.5)}% sur ${rates[rates.length - 1].engine}`,
552→      });
553→    }
554→  }
555→
556→  // OPPORTUNITÉ 3 : Anglais absent (si applicable)
557→  const enSummary = summaries.find(s => s.language === 'en');
558→  if (enSummary && enSummary.overallRate < 10) {
559→    opportunities.push({
560→      type: 'language_gap',
561→      severity: 'high',
562→      language: 'en',
563→      title: 'Absent des citations en anglais',
564→      description: `68% des requêtes aux moteurs IA sont en anglais. Votre taux de citation en anglais est de ${enSummary.overallRate}%. Vous manquez le plus gros marché mondial.`,
565→      action: 'Créer des pages EN avec FAQ en anglais, Schema.org en anglais, contenu answer-first traduit.',
566→      estimatedImpact: '+40% de reach potentiel global',
567→    });
568→  }
569→
570→  // OPPORTUNITÉ 4 : Concurrents dominant dans une langue
571→  for (const summary of summaries) {
572→    if (summary.topCompetitors.length > 0 && summary.overallRate < 30) {
573→      const langLabel = SUPPORTED_LANGUAGES_MAP[summary.language] || summary.language;
574→      opportunities.push({
575→        type: 'competitor_threat',
576→        severity: summary.overallRate < 10 ? 'high' : 'medium',
577→        language: summary.language,
578→        title: `Concurrents dominants en ${langLabel}`,
579→        description: `En ${langLabel}, les IA recommandent principalement : ${summary.topCompetitors.slice(0, 3).join(', ')}. Vous n'êtes cité qu'à ${summary.overallRate}%.`,
580→        action: `Créer du contenu comparatif en ${langLabel} positionnant ${config.brand} face à ces concurrents.`,
581→        estimatedImpact: `Récupérer des citations face à ${summary.topCompetitors[0]}`,
582→      });
583→    }
584→  }
585→
586→  // Trier par sévérité
587→  const severityOrder = { high: 0, medium: 1, low: 2 };
588→  opportunities.sort((a, b) => severityOrder[a.severity] - severityOrder[b.severity]);
589→
590→  return opportunities;
591→}
592→
593→// ═══ STATS GLOBALES ═══
594→
595→function computeGlobalStats(summaries: LanguageSummary[]) {
596→  const sorted = [...summaries].sort((a, b) => b.overallRate - a.overallRate);
597→  const totalQueries = summaries.reduce((s, l) => s + l.totalQueries, 0);
598→  const totalCitations = summaries.reduce((s, l) => {
599→    const engines = ['chatgpt', 'perplexity', 'gemini'] as const;
600→    return s + engines.reduce((es, e) => es + l.citationsByEngine[e].cited, 0);
601→  }, 0);
602→
603→  return {
604→    bestLanguage: { code: sorted[0]?.language || 'fr', rate: sorted[0]?.overallRate || 0 },
605→    worstLanguage: { code: sorted[sorted.length - 1]?.language || 'en', rate: sorted[sorted.length - 1]?.overallRate || 0 },
606→    averageRate: Math.round(summaries.reduce((s, l) => s + l.overallRate, 0) / (summaries.length || 1)),
607→    totalQueriesRun: totalQueries,
608→    totalCitations,
609→  };
610→}
611→
612→// Helper pour les labels
613→const SUPPORTED_LANGUAGES_MAP: Record<string, string> = {
