// Coût dynamique
const creditCost = config.languages.length * 3;

// Lancer l'analyse
async function handleAnalyze() {
  if (credits < creditCost) {
    // Afficher message "pas assez de crédits"
    return;
  }
  setIsRunning(true);
  try {
    const result = await runMultilingualCheck(config, setProgress);
