export interface CitationConfig {
  brandName: string;
  brandUrl: string;
  brandVariants?: string[];
  productsServices?: string[];
  competitors?: string[];
}

export interface CitationDetection {
  urlExactMatch: boolean;
  urlPartialMatch: boolean;
  urlInSource: boolean;
  brandExactMatch: boolean;
  brandVariants: string[];
  brandContext: 'recommendation' | 'mention' | 'comparison' | 'negative';
  productsServicesFound: string[];
  positionInResponse: 'first_paragraph' | 'middle' | 'end' | 'footnote';
  isTopRecommendation: boolean;
  competitorsBeforeUs: string[];
  sentiment: 'positive' | 'neutral' | 'negative';
  detailLevel: 'detailed' | 'brief' | 'passing_mention';
  citationScore: number;
}

const POSITIVE_SIGNALS = [
  'recommend', 'best', 'top', 'excellent', 'great', 'leading', 'trusted',
  'popular', 'reliable', 'innovative', 'standout', 'preferred',
  'recommande', 'meilleur', 'excellent', 'fiable', 'leader', 'innovant',
];

const NEGATIVE_SIGNALS = [
  'avoid', 'worst', 'poor', 'unreliable', 'expensive', 'limited',
  'outdated', 'problematic', 'issues', 'complaints',
  'éviter', 'mauvais', 'cher', 'limité', 'obsolète', 'problème',
];

