function getPosition(text: string, matchIndex: number): CitationDetection['positionInResponse'] {
  const totalLength = text.length;
  if (matchIndex === -1) return 'middle';

  const ratio = matchIndex / totalLength;
  const paragraphs = text.split(/\n\n+/);
  const firstParaEnd = paragraphs[0]?.length || 0;

  if (matchIndex <= firstParaEnd) return 'first_paragraph';
  if (ratio > 0.85) return 'footnote';
  if (ratio > 0.65) return 'end';
  return 'middle';
}

