// services/v3/language-query-templates.ts
//
// Templates de requetes multilingues pour tester les citations.
// Chaque template a un {brand}, {domain} et {industry} a remplacer.
// La requete est posee DANS LA LANGUE CIBLE a chaque moteur IA.

export interface QueryTemplate {
  id: string;
  category: 'informational' | 'comparative' | 'transactional' | 'reputation';
  template: Record<string, string>;  // code langue -> template de requete
  weight: number;  // importance de cette requete (1.0 = standard, 1.5 = haute)
}

export const SUPPORTED_LANGUAGES = [
  { code: 'fr', label: 'Francais',    flag: '\u{1F1EB}\u{1F1F7}', queryLang: 'en francais' },
  { code: 'en', label: 'English',     flag: '\u{1F1EC}\u{1F1E7}', queryLang: 'in English' },
  { code: 'es', label: 'Espanol',     flag: '\u{1F1EA}\u{1F1F8}', queryLang: 'en espanol' },
  { code: 'de', label: 'Deutsch',     flag: '\u{1F1E9}\u{1F1EA}', queryLang: 'auf Deutsch' },
  { code: 'it', label: 'Italiano',    flag: '\u{1F1EE}\u{1F1F9}', queryLang: 'in italiano' },
  { code: 'pt', label: 'Portugues',   flag: '\u{1F1E7}\u{1F1F7}', queryLang: 'em portugues' },
  { code: 'nl', label: 'Nederlands',  flag: '\u{1F1F3}\u{1F1F1}', queryLang: 'in het Nederlands' },
  { code: 'ar', label: '\u0627\u0644\u0639\u0631\u0628\u064A\u0629',       flag: '\u{1F1F8}\u{1F1E6}', queryLang: '\u0628\u0627\u0644\u0639\u0631\u0628\u064A\u0629' },
  { code: 'ja', label: '\u65E5\u672C\u8A9E',      flag: '\u{1F1EF}\u{1F1F5}', queryLang: '\u65E5\u672C\u8A9E\u3067' },
  { code: 'zh', label: '\u4E2D\u6587',        flag: '\u{1F1E8}\u{1F1F3}', queryLang: '\u7528\u4E2D\u6587' },
] as const;

export type LanguageCode = typeof SUPPORTED_LANGUAGES[number]['code'];

// 5 requetes types, chacune traduite dans les 10 langues
export const MULTILINGUAL_QUERY_TEMPLATES: QueryTemplate[] = [

  // === REQUETE 1 --- INFORMATIONNELLE (generique au secteur) ===
  {
    id: 'info-best-tools',
    category: 'informational',
    weight: 1.5,
    template: {
      fr: "Quels sont les meilleurs outils de {industry} ?",
      en: "What are the best {industry} tools?",
      es: "\u00BFCu\u00E1les son las mejores herramientas de {industry}?",
      de: "Was sind die besten {industry}-Tools?",
      it: "Quali sono i migliori strumenti di {industry}?",
      pt: "Quais s\u00E3o as melhores ferramentas de {industry}?",
      nl: "Wat zijn de beste {industry} tools?",
      ar: "\u0645\u0627 \u0647\u064A \u0623\u0641\u0636\u0644 \u0623\u062F\u0648\u0627\u062A {industry}\u061F",
      ja: "{industry}\u306E\u6700\u826F\u306E\u30C4\u30FC\u30EB\u306F\u4F55\u3067\u3059\u304B\uFF1F",
      zh: "{industry}\u6700\u597D\u7684\u5DE5\u5177\u6709\u54EA\u4E9B\uFF1F",
    },
  },

  // === REQUETE 2 --- COMPARATIVE (marque vs alternatives) ===
  {
    id: 'comp-alternatives',
    category: 'comparative',
    weight: 1.5,
    template: {
      fr: "Quelles sont les alternatives \u00E0 {brand} ?",
      en: "What are the alternatives to {brand}?",
      es: "\u00BFCu\u00E1les son las alternativas a {brand}?",
      de: "Was sind die Alternativen zu {brand}?",
      it: "Quali sono le alternative a {brand}?",
      pt: "Quais s\u00E3o as alternativas ao {brand}?",
      nl: "Wat zijn de alternatieven voor {brand}?",
      ar: "\u0645\u0627 \u0647\u064A \u0628\u062F\u0627\u0626\u0644 {brand}\u061F",
      ja: "{brand}\u306E\u4EE3\u66FF\u54C1\u306F\u4F55\u3067\u3059\u304B\uFF1F",
      zh: "{brand}\u6709\u54EA\u4E9B\u66FF\u4EE3\u54C1\uFF1F",
    },
  },

  // === REQUETE 3 --- TRANSACTIONNELLE (recommandation directe) ===
  {
    id: 'trans-recommend',
    category: 'transactional',
    weight: 1.0,
    template: {
      fr: "Quel {industry} me recommandes-tu pour {useCase} ?",
      en: "Which {industry} tool would you recommend for {useCase}?",
      es: "\u00BFQu\u00E9 herramienta de {industry} me recomiendas para {useCase}?",
      de: "Welches {industry}-Tool empfiehlst du mir f\u00FCr {useCase}?",
      it: "Quale strumento di {industry} consigli per {useCase}?",
      pt: "Qual ferramenta de {industry} voc\u00EA recomenda para {useCase}?",
      nl: "Welke {industry} tool raad je aan voor {useCase}?",
      ar: "\u0645\u0627 \u0623\u062F\u0627\u0629 {industry} \u0627\u0644\u062A\u064A \u062A\u0648\u0635\u064A \u0628\u0647\u0627 \u0644\u0640 {useCase}\u061F",
      ja: "{useCase}\u306E\u305F\u3081\u306B{industry}\u306E\u3069\u306E\u30C4\u30FC\u30EB\u3092\u304A\u52E7\u3081\u3057\u307E\u3059\u304B\uFF1F",
      zh: "\u4F60\u63A8\u8350\u54EA\u4E2A{industry}\u5DE5\u5177\u7528\u4E8E{useCase}\uFF1F",
    },
  },

  // === REQUETE 4 --- REPUTATION (avis et opinion) ===
  {
    id: 'rep-opinion',
    category: 'reputation',
    weight: 1.0,
    template: {
      fr: "Que penses-tu de {brand} pour {industry} ?",
      en: "What do you think of {brand} for {industry}?",
      es: "\u00BFQu\u00E9 opinas de {brand} para {industry}?",
      de: "Was h\u00E4ltst du von {brand} f\u00FCr {industry}?",
      it: "Cosa pensi di {brand} per {industry}?",
      pt: "O que voc\u00EA acha do {brand} para {industry}?",
      nl: "Wat vind je van {brand} voor {industry}?",
      ar: "\u0645\u0627 \u0631\u0623\u064A\u0643 \u0641\u064A {brand} \u0644\u0640 {industry}\u061F",
      ja: "{industry}\u306E\u305F\u3081\u306E{brand}\u306B\u3064\u3044\u3066\u3069\u3046\u601D\u3044\u307E\u3059\u304B\uFF1F",
      zh: "\u4F60\u89C9\u5F97{brand}\u5728{industry}\u65B9\u9762\u600E\u4E48\u6837\uFF1F",
    },
  },

  // === REQUETE 5 --- INFORMATIONNELLE (domaine specifique) ===
  {
    id: 'info-how-to',
    category: 'informational',
    weight: 1.0,
    template: {
      fr: "Comment am\u00E9liorer {useCase} avec un outil de {industry} ?",
      en: "How to improve {useCase} with a {industry} tool?",
      es: "\u00BFC\u00F3mo mejorar {useCase} con una herramienta de {industry}?",
      de: "Wie kann man {useCase} mit einem {industry}-Tool verbessern?",
      it: "Come migliorare {useCase} con uno strumento di {industry}?",
      pt: "Como melhorar {useCase} com uma ferramenta de {industry}?",
      nl: "Hoe {useCase} verbeteren met een {industry} tool?",
      ar: "\u0643\u064A\u0641 \u064A\u0645\u0643\u0646 \u062A\u062D\u0633\u064A\u0646 {useCase} \u0628\u0627\u0633\u062A\u062E\u062F\u0627\u0645 \u0623\u062F\u0627\u0629 {industry}\u061F",
      ja: "{industry}\u30C4\u30FC\u30EB\u3067{useCase}\u3092\u6539\u5584\u3059\u308B\u306B\u306F\uFF1F",
      zh: "\u5982\u4F55\u4F7F\u7528{industry}\u5DE5\u5177\u6539\u5584{useCase}\uFF1F",
    },
  },
];

// Remplacer les placeholders dans un template
export function buildQuery(
  template: string,
  vars: { brand: string; domain?: string; industry: string; useCase?: string }
): string {
  return template
    .replace(/{brand}/g, vars.brand)
    .replace(/{domain}/g, vars.domain || vars.brand)
    .replace(/{industry}/g, vars.industry)
    .replace(/{useCase}/g, vars.useCase || vars.industry);
}

