// services/v3/multilingual-checker.ts
//
// Orchestre l'analyse de citations multilingue.
// Pour chaque langue selectionnee :
//   1. Genere les 5 requetes dans cette langue
//   2. Interroge les 3 moteurs IA
//   3. Analyse les reponses (citation detectee ou non)
//   4. Calcule le taux de citation par langue x moteur
//
// Utilise le proxy securise (lib/ai-proxy.ts) pour tous les appels.

import { callChatGPT, callPerplexity, callGemini } from '../../lib/ai-proxy';
import { MULTILINGUAL_QUERY_TEMPLATES, buildQuery, SUPPORTED_LANGUAGES, type LanguageCode } from './language-query-templates';
// Reutiliser le detecteur de citations existant
import { detectCitation, type CitationConfig } from './citation-detector';

// === TYPES ===

export interface MultilingualConfig {
  url: string;
  brand: string;
  industry: string;
  useCase?: string;
  languages: LanguageCode[];
}

export interface LanguageCitationResult {
  language: LanguageCode;
  engine: 'chatgpt' | 'perplexity' | 'gemini';
  query: string;
  queryId: string;
  category: string;
  response: string;
  cited: boolean;
  citationType: 'url' | 'brand' | 'product' | 'none';
  position: 'first' | 'mentioned' | 'absent';
  sentiment: 'positive' | 'neutral' | 'negative' | 'absent';
  competitorsCited: string[];
}

export interface LanguageSummary {
  language: LanguageCode;
  totalQueries: number;
  citationsByEngine: {
    chatgpt: { cited: number; total: number; rate: number };
    perplexity: { cited: number; total: number; rate: number };
    gemini: { cited: number; total: number; rate: number };
  };
  overallRate: number;
  topCompetitors: string[];
  bestCategory: string;
  worstCategory: string;
}

export interface MultilingualReport {
  config: MultilingualConfig;
  timestamp: string;
  results: LanguageCitationResult[];
  summaryByLanguage: LanguageSummary[];
  opportunities: Opportunity[];
  globalStats: {
    bestLanguage: { code: LanguageCode; rate: number };
    worstLanguage: { code: LanguageCode; rate: number };
    averageRate: number;
    totalQueriesRun: number;
    totalCitations: number;
  };
}

export interface Opportunity {
  type: 'language_gap' | 'engine_gap' | 'category_gap' | 'competitor_threat';
  severity: 'high' | 'medium' | 'low';
  language: LanguageCode;
  engine?: string;
  title: string;
  description: string;
  action: string;
  estimatedImpact: string;
}

// === WRAPPER pour adapter detectCitation a notre interface ===
// detectCitation attend (responseText, responseSources[], CitationConfig)
// On adapte pour retourner un format simplifie

function adaptDetectCitation(
  responseText: string,
  brandUrl: string,
  brandName: string
): {
  found: boolean;
  type: 'url' | 'brand' | 'product' | 'none';
  position: 'first' | 'mentioned' | 'absent';
  sentiment: 'positive' | 'neutral' | 'negative' | 'absent';
  competitors: string[];
} {
  const config: CitationConfig = {
    brandName,
    brandUrl,
    brandVariants: [],
    productsServices: [],
    competitors: [],
  };

  try {
    const detection = detectCitation(responseText, [], config);
    const found = detection.urlExactMatch || detection.urlPartialMatch || detection.brandExactMatch;
    const type = detection.urlExactMatch ? 'url' : detection.brandExactMatch ? 'brand' : 'none';
    const position = detection.positionInResponse === 'first_paragraph' ? 'first' as const
      : found ? 'mentioned' as const : 'absent' as const;
    const sentiment = found ? detection.sentiment : 'absent' as const;

    return {
      found,
      type,
      position,
      sentiment,
      competitors: detection.competitorsBeforeUs || [],
    };
  } catch {
    return { found: false, type: 'none', position: 'absent', sentiment: 'absent', competitors: [] };
  }
}

// === ORCHESTRATEUR PRINCIPAL ===

export async function runMultilingualCheck(
  config: MultilingualConfig,
  onProgress?: (progress: {
    current: number;
    total: number;
    language: string;
    engine: string;
    status: string;
  }) => void
): Promise<MultilingualReport> {

  const results: LanguageCitationResult[] = [];
  const engines = ['chatgpt', 'perplexity', 'gemini'] as const;

  const totalSteps = config.languages.length * MULTILINGUAL_QUERY_TEMPLATES.length * engines.length;
  let currentStep = 0;

  // Pour chaque langue
  for (const lang of config.languages) {
    // Pour chaque template de requete
    for (const template of MULTILINGUAL_QUERY_TEMPLATES) {
      const queryText = template.template[lang];
      if (!queryText) continue;

      const query = buildQuery(queryText, {
        brand: config.brand,
        industry: config.industry,
        useCase: config.useCase,
      });

      // Pour chaque moteur IA
      for (const engine of engines) {
        currentStep++;

        onProgress?.({
          current: currentStep,
          total: totalSteps,
          language: lang,
          engine,
          status: `Interrogation ${engine} en ${lang}...`,
        });

        try {
          // Rate limiting entre les appels
          const delay = engine === 'perplexity' ? 500 : engine === 'chatgpt' ? 200 : 100;
          await new Promise(r => setTimeout(r, delay));

          // Appeler le moteur via le proxy securise
          let response: string;
          switch (engine) {
            case 'chatgpt':
              response = await callChatGPT(query);
              break;
            case 'perplexity':
              response = await callPerplexity(query);
              break;
            case 'gemini':
              response = await callGemini(query);
              break;
          }

          // Analyser la citation via le wrapper
          const citation = adaptDetectCitation(response, config.url, config.brand);

          results.push({
            language: lang,
            engine,
            query,
            queryId: template.id,
            category: template.category,
            response,
            cited: citation.found,
            citationType: citation.type,
            position: citation.position,
            sentiment: citation.sentiment,
            competitorsCited: citation.competitors,
          });

        } catch (error) {
          results.push({
            language: lang,
            engine,
            query,
            queryId: template.id,
            category: template.category,
            response: `[Error: ${error instanceof Error ? error.message : 'Unknown'}]`,
            cited: false,
            citationType: 'none',
            position: 'absent',
            sentiment: 'absent',
            competitorsCited: [],
          });
        }
      }
    }
  }

  // === AGREGATION ===

  const summaryByLanguage = aggregateByLanguage(results, config.languages);
  const opportunities = identifyOpportunities(summaryByLanguage, config);
  const globalStats = computeGlobalStats(summaryByLanguage);

  return {
    config,
    timestamp: new Date().toISOString(),
    results,
    summaryByLanguage,
    opportunities,
    globalStats,
  };
}

// === AGREGATION PAR LANGUE ===

function aggregateByLanguage(
  results: LanguageCitationResult[],
  languages: LanguageCode[]
): LanguageSummary[] {
  return languages.map(lang => {
    const langResults = results.filter(r => r.language === lang);
    const engines = ['chatgpt', 'perplexity', 'gemini'] as const;

    const citationsByEngine = {} as LanguageSummary['citationsByEngine'];

    for (const engine of engines) {
      const engineResults = langResults.filter(r => r.engine === engine);
      const cited = engineResults.filter(r => r.cited).length;
      const total = engineResults.length;
      citationsByEngine[engine] = {
        cited,
        total,
        rate: total > 0 ? Math.round((cited / total) * 100) : 0,
      };
    }

    const totalCited = langResults.filter(r => r.cited).length;
    const totalQueries = langResults.length;
    const overallRate = totalQueries > 0 ? Math.round((totalCited / totalQueries) * 100) : 0;

    // Concurrents les plus cites
    const competitorCounts: Record<string, number> = {};
    for (const r of langResults) {
      for (const comp of r.competitorsCited) {
        competitorCounts[comp] = (competitorCounts[comp] || 0) + 1;
      }
    }
    const topCompetitors = Object.entries(competitorCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5)
      .map(([name]) => name);

    // Meilleure et pire categorie
    const categories = ['informational', 'comparative', 'transactional', 'reputation'];
    const categoryRates = categories.map(cat => {
      const catResults = langResults.filter(r => r.category === cat);
      const catCited = catResults.filter(r => r.cited).length;
      return { category: cat, rate: catResults.length > 0 ? catCited / catResults.length : 0 };
    });
    categoryRates.sort((a, b) => b.rate - a.rate);

    return {
      language: lang,
      totalQueries,
      citationsByEngine,
      overallRate,
      topCompetitors,
      bestCategory: categoryRates[0]?.category || 'N/A',
      worstCategory: categoryRates[categoryRates.length - 1]?.category || 'N/A',
    };
  });
}

// === IDENTIFICATION DES OPPORTUNITES ===

function identifyOpportunities(
  summaries: LanguageSummary[],
  config: MultilingualConfig
): Opportunity[] {
  const opportunities: Opportunity[] = [];

  if (summaries.length < 2) return opportunities;

  const sorted = [...summaries].sort((a, b) => b.overallRate - a.overallRate);
  const bestLang = sorted[0];
  const worstLang = sorted[sorted.length - 1];

  // OPPORTUNITE 1 : Gap entre meilleure et pire langue
  if (bestLang && worstLang && bestLang.overallRate - worstLang.overallRate > 20) {
    const langLabel = SUPPORTED_LANGUAGES_MAP[worstLang.language] || worstLang.language;
    const bestLabel = SUPPORTED_LANGUAGES_MAP[bestLang.language] || bestLang.language;

    opportunities.push({
      type: 'language_gap',
      severity: bestLang.overallRate - worstLang.overallRate > 40 ? 'high' : 'medium',
      language: worstLang.language,
      title: `Invisible en ${langLabel}`,
      description: `Vous etes cite a ${bestLang.overallRate}% en ${bestLabel} mais seulement ${worstLang.overallRate}% en ${langLabel}. C'est un marche entier que vous ne captez pas.`,
      action: `Creer du contenu optimise AEO en ${langLabel} : FAQ, Schema.org multilingue, page answer-first dediee.`,
      estimatedImpact: `+${Math.round((bestLang.overallRate - worstLang.overallRate) * 0.6)}% de citations potentielles en ${langLabel}`,
    });
  }

  // OPPORTUNITE 2 : Gap par moteur dans une langue
  for (const summary of summaries) {
    const engines = ['chatgpt', 'perplexity', 'gemini'] as const;
    const rates = engines.map(e => ({ engine: e, rate: summary.citationsByEngine[e].rate }));
    rates.sort((a, b) => b.rate - a.rate);

    if (rates[0].rate - rates[rates.length - 1].rate > 30) {
      const langLabel = SUPPORTED_LANGUAGES_MAP[summary.language] || summary.language;
      opportunities.push({
        type: 'engine_gap',
        severity: 'medium',
        language: summary.language,
        engine: rates[rates.length - 1].engine,
        title: `${rates[rates.length - 1].engine} ne vous cite pas en ${langLabel}`,
        description: `En ${langLabel}, ${rates[0].engine} vous cite a ${rates[0].rate}% mais ${rates[rates.length - 1].engine} seulement a ${rates[rates.length - 1].rate}%.`,
        action: `Optimiser le contenu ${langLabel} selon les criteres specifiques de ${rates[rates.length - 1].engine}.`,
        estimatedImpact: `+${Math.round((rates[0].rate - rates[rates.length - 1].rate) * 0.5)}% sur ${rates[rates.length - 1].engine}`,
      });
    }
  }

  // OPPORTUNITE 3 : Anglais absent
  const enSummary = summaries.find(s => s.language === 'en');
  if (enSummary && enSummary.overallRate < 10) {
    opportunities.push({
      type: 'language_gap',
      severity: 'high',
      language: 'en',
      title: 'Absent des citations en anglais',
      description: `68% des requetes aux moteurs IA sont en anglais. Votre taux de citation en anglais est de ${enSummary.overallRate}%. Vous manquez le plus gros marche mondial.`,
      action: 'Creer des pages EN avec FAQ en anglais, Schema.org en anglais, contenu answer-first traduit.',
      estimatedImpact: '+40% de reach potentiel global',
    });
  }

  // OPPORTUNITE 4 : Concurrents dominant dans une langue
  for (const summary of summaries) {
    if (summary.topCompetitors.length > 0 && summary.overallRate < 30) {
      const langLabel = SUPPORTED_LANGUAGES_MAP[summary.language] || summary.language;
      opportunities.push({
        type: 'competitor_threat',
        severity: summary.overallRate < 10 ? 'high' : 'medium',
        language: summary.language,
        title: `Concurrents dominants en ${langLabel}`,
        description: `En ${langLabel}, les IA recommandent principalement : ${summary.topCompetitors.slice(0, 3).join(', ')}. Vous n'etes cite qu'a ${summary.overallRate}%.`,
        action: `Creer du contenu comparatif en ${langLabel} positionnant ${config.brand} face a ces concurrents.`,
        estimatedImpact: `Recuperer des citations face a ${summary.topCompetitors[0]}`,
      });
    }
  }

  const severityOrder = { high: 0, medium: 1, low: 2 };
  opportunities.sort((a, b) => severityOrder[a.severity] - severityOrder[b.severity]);

  return opportunities;
}

// === STATS GLOBALES ===

function computeGlobalStats(summaries: LanguageSummary[]) {
  const sorted = [...summaries].sort((a, b) => b.overallRate - a.overallRate);
  const totalQueries = summaries.reduce((s, l) => s + l.totalQueries, 0);
  const totalCitations = summaries.reduce((s, l) => {
    const engines = ['chatgpt', 'perplexity', 'gemini'] as const;
    return s + engines.reduce((es, e) => es + l.citationsByEngine[e].cited, 0);
  }, 0);

  return {
    bestLanguage: { code: sorted[0]?.language || ('fr' as LanguageCode), rate: sorted[0]?.overallRate || 0 },
    worstLanguage: { code: sorted[sorted.length - 1]?.language || ('en' as LanguageCode), rate: sorted[sorted.length - 1]?.overallRate || 0 },
    averageRate: Math.round(summaries.reduce((s, l) => s + l.overallRate, 0) / (summaries.length || 1)),
    totalQueriesRun: totalQueries,
    totalCitations,
  };
}

// Helper pour les labels
const SUPPORTED_LANGUAGES_MAP: Record<string, string> = {
  fr: 'francais', en: 'anglais', es: 'espagnol', de: 'allemand',
  it: 'italien', pt: 'portugais', nl: 'neerlandais', ar: 'arabe',
  ja: 'japonais', zh: 'chinois',
};

