// components/LanguageCitationMatrix.tsx
// Matrice de citations par langue x moteur IA

import React from 'react';
import { SUPPORTED_LANGUAGES } from '../services/v3/language-query-templates';
import type { LanguageSummary } from '../services/v3/multilingual-checker';

interface Props {
  summaries: LanguageSummary[];
}

function rateColor(rate: number): string {
  if (rate >= 50) return 'text-emerald-400';
  if (rate >= 20) return 'text-amber-400';
  if (rate > 0) return 'text-red-400';
  return 'text-zinc-600';
}

function barColor(engine: 'chatgpt' | 'perplexity' | 'gemini'): string {
  switch (engine) {
    case 'chatgpt': return 'bg-emerald-500';
    case 'perplexity': return 'bg-blue-500';
    case 'gemini': return 'bg-purple-500';
  }
}

function EngineCell({ rate, engine }: { rate: number; engine: 'chatgpt' | 'perplexity' | 'gemini' }) {
  return (
    <div className="flex items-center gap-3">
      <div className="w-full max-w-[120px] h-2 rounded-full bg-white/[0.06]">
        <div
          className={`h-full rounded-full ${barColor(engine)} transition-all duration-500 ease-out`}
          style={{ width: `${rate}%` }}
        />
      </div>
      <span className={`text-[13px] font-mono font-medium min-w-[36px] text-right ${rateColor(rate)}`}>
        {rate}%
      </span>
    </div>
  );
}

export default function LanguageCitationMatrix({ summaries }: Props) {
  if (!summaries.length) return null;

  return (
    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
      {/* Header */}
      <div className="px-6 py-4 border-b border-white/[0.06] flex justify-between items-center">
        <div>
          <h3 className="text-white font-semibold">Matrice de citations par langue</h3>
          <p className="text-[13px] text-zinc-500 mt-0.5">Taux de citation par moteur IA et langue</p>
        </div>
        <div className="flex items-center gap-4 text-[11px] text-zinc-500">
          <span className="flex items-center gap-1.5"><span className="w-2 h-2 rounded-full bg-emerald-500" /> ChatGPT</span>
          <span className="flex items-center gap-1.5"><span className="w-2 h-2 rounded-full bg-blue-500" /> Perplexity</span>
          <span className="flex items-center gap-1.5"><span className="w-2 h-2 rounded-full bg-purple-500" /> Gemini</span>
        </div>
      </div>

      {/* Column headers */}
      <div className="grid grid-cols-[200px_1fr_1fr_1fr_80px] px-6 py-3 border-b border-white/[0.04] text-[11px] uppercase tracking-wider text-zinc-600 font-medium">
        <span>Langue</span>
        <span>ChatGPT</span>
        <span>Perplexity</span>
        <span>Gemini</span>
        <span className="text-right">Moyenne</span>
      </div>

      {/* Rows */}
      {summaries.map((summary, idx) => {
        const langInfo = SUPPORTED_LANGUAGES.find(l => l.code === summary.language);
        const isLast = idx === summaries.length - 1;

        return (
          <div
            key={summary.language}
            className={`grid grid-cols-[200px_1fr_1fr_1fr_80px] px-6 py-4 items-center hover:bg-white/[0.02] transition-colors duration-150 ${
              !isLast ? 'border-b border-white/[0.04]' : ''
            }`}
          >
            <div className="flex items-center gap-2">
              <span className="text-lg">{langInfo?.flag}</span>
              <span className="text-[14px] text-zinc-300">{langInfo?.label || summary.language}</span>
            </div>

            <EngineCell rate={summary.citationsByEngine.chatgpt.rate} engine="chatgpt" />
            <EngineCell rate={summary.citationsByEngine.perplexity.rate} engine="perplexity" />
            <EngineCell rate={summary.citationsByEngine.gemini.rate} engine="gemini" />

            <span className={`text-[14px] font-semibold text-right ${rateColor(summary.overallRate)}`}>
              {summary.overallRate}%
            </span>
          </div>
        );
      })}
    </div>
  );
}

