// pages/MultilingualCitations.tsx
// Analyse de citations multilingues — matrice langue x moteur IA

import React, { useState } from 'react';
import { Globe, Play, ChevronDown, ChevronUp, CheckCircle, XCircle, Loader2 } from 'lucide-react';
import { SUPPORTED_LANGUAGES, type LanguageCode } from '../services/v3/language-query-templates';
import { runMultilingualCheck, type MultilingualConfig, type MultilingualReport, type LanguageCitationResult } from '../services/v3/multilingual-checker';
import LanguageCitationMatrix from '../components/LanguageCitationMatrix';
import LanguageOpportunityCard from '../components/LanguageOpportunityCard';

interface Props {
  onBack?: () => void;
  user: { name: string; email: string } | null;
  onDeductCredits?: (amount: number) => void;
}

export default function MultilingualCitations({ onBack, user, onDeductCredits }: Props) {
  // === CONFIG STATE ===
  const [url, setUrl] = useState('');
  const [brand, setBrand] = useState('');
  const [industry, setIndustry] = useState('');
  const [useCase, setUseCase] = useState('');
  const [selectedLanguages, setSelectedLanguages] = useState<LanguageCode[]>(['fr', 'en']);

  // === ANALYSIS STATE ===
  const [isRunning, setIsRunning] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, language: '', engine: '', status: '' });
  const [report, setReport] = useState<MultilingualReport | null>(null);
  const [expandedLanguage, setExpandedLanguage] = useState<string | null>(null);

  const creditCost = selectedLanguages.length * 3;

  function toggleLanguage(code: LanguageCode) {
    setSelectedLanguages(prev =>
      prev.includes(code) ? prev.filter(l => l !== code) : [...prev, code]
    );
  }

  async function handleAnalyze() {
    if (!url || !brand || !industry || selectedLanguages.length === 0) return;

    setIsRunning(true);
    setReport(null);
    try {
      const config: MultilingualConfig = {
        url, brand, industry, useCase: useCase || undefined,
        languages: selectedLanguages,
      };
      const result = await runMultilingualCheck(config, setProgress);
      setReport(result);
      onDeductCredits?.(creditCost);
    } catch (error) {
      console.error('Multilingual check failed:', error);
    } finally {
      setIsRunning(false);
    }
  }

  // Grouper les resultats par langue pour le detail accordion
  function getResultsByLanguage(lang: string): LanguageCitationResult[] {
    return report?.results.filter(r => r.language === lang) || [];
  }

  return (
    <div className="space-y-6 page-enter">

      {/* === HEADER === */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <Globe className="w-6 h-6 text-blue-400" />
            Citations par langue
          </h1>
          <p className="text-[14px] text-zinc-400 mt-1">
            Analysez votre visibilite dans les moteurs IA par langue
          </p>
        </div>
        {report && (
          <div className="text-right">
            <div className="text-[13px] text-zinc-500">Analyse du</div>
            <div className="text-[14px] text-zinc-300 font-medium">
              {new Date(report.timestamp).toLocaleDateString('fr-FR')}
            </div>
          </div>
        )}
      </div>

      {/* === CONFIGURATION === */}
      <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
        <h2 className="text-white font-semibold mb-4">Configuration</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
          <div>
            <label className="block text-[13px] text-zinc-400 mb-1.5">URL du site</label>
            <input
              type="url"
              value={url}
              onChange={e => setUrl(e.target.value)}
              placeholder="https://example.com"
              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
            />
          </div>
          <div>
            <label className="block text-[13px] text-zinc-400 mb-1.5">Nom de la marque</label>
            <input
              type="text"
              value={brand}
              onChange={e => setBrand(e.target.value)}
              placeholder="Ma Marque"
              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
            />
          </div>
          <div>
            <label className="block text-[13px] text-zinc-400 mb-1.5">Secteur / Industrie</label>
            <input
              type="text"
              value={industry}
              onChange={e => setIndustry(e.target.value)}
              placeholder="SaaS, Marketing digital, E-commerce..."
              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
            />
          </div>
          <div>
            <label className="block text-[13px] text-zinc-400 mb-1.5">Cas d'usage <span className="text-zinc-600">(optionnel)</span></label>
            <input
              type="text"
              value={useCase}
              onChange={e => setUseCase(e.target.value)}
              placeholder="SEO, gestion de projet..."
              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
            />
          </div>
        </div>

        {/* Language selection */}
        <div className="mb-6">
          <label className="block text-[13px] text-zinc-400 mb-3">Langues a analyser</label>
          <div className="flex flex-wrap gap-2">
            {SUPPORTED_LANGUAGES.map(lang => {
              const isSelected = selectedLanguages.includes(lang.code as LanguageCode);
              return (
                <button
                  key={lang.code}
                  onClick={() => toggleLanguage(lang.code as LanguageCode)}
                  className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[13px] font-medium transition-all duration-150 cursor-pointer ${
                    isSelected
                      ? 'bg-blue-500/15 text-blue-400 border border-blue-500/30'
                      : 'bg-white/[0.03] text-zinc-500 border border-white/[0.06] hover:text-zinc-300 hover:border-white/[0.1]'
                  }`}
                >
                  <span>{lang.flag}</span>
                  <span>{lang.label}</span>
                </button>
              );
            })}
          </div>
        </div>

        {/* Cost + Launch */}
        <div className="flex items-center justify-between pt-4 border-t border-white/[0.06]">
          <div className="text-[14px] text-zinc-400">
            Cout : <span className="text-white font-medium">{creditCost} credits</span>
            <span className="text-zinc-600 ml-1">(3 credits x {selectedLanguages.length} langue{selectedLanguages.length > 1 ? 's' : ''})</span>
          </div>
          <button
            onClick={handleAnalyze}
            disabled={isRunning || !url || !brand || !industry || selectedLanguages.length === 0}
            className="flex items-center gap-2 px-5 py-2.5 rounded-lg bg-white text-black font-medium text-[14px] hover:bg-gray-200 disabled:opacity-40 disabled:cursor-not-allowed transition-all cursor-pointer press-effect"
          >
            {isRunning ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                Analyse en cours...
              </>
            ) : (
              <>
                <Play className="w-4 h-4" />
                Lancer l'analyse — {creditCost} credits
              </>
            )}
          </button>
        </div>
      </div>

      {/* === PROGRESS BAR === */}
      {isRunning && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-[14px] text-white font-medium">
              Analyse en cours... {progress.current}/{progress.total} requetes
            </span>
            <span className="text-[13px] text-zinc-500">
              {Math.round((progress.current / Math.max(progress.total, 1)) * 100)}%
            </span>
          </div>
          <div className="h-2 rounded-full bg-white/[0.06] overflow-hidden">
            <div
              className="h-full rounded-full bg-blue-500 transition-all duration-300 skeleton-shimmer"
              style={{ width: `${(progress.current / Math.max(progress.total, 1)) * 100}%` }}
            />
          </div>
          <p className="text-[13px] text-zinc-500 mt-2">
            {progress.status}
          </p>
        </div>
      )}

      {/* === RESULTATS === */}
      {report && (
        <>
          {/* Global stats */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <StatCard
              label="Meilleure langue"
              value={`${SUPPORTED_LANGUAGES.find(l => l.code === report.globalStats.bestLanguage.code)?.flag || ''} ${report.globalStats.bestLanguage.rate}%`}
              color="text-emerald-400"
            />
            <StatCard
              label="Pire langue"
              value={`${SUPPORTED_LANGUAGES.find(l => l.code === report.globalStats.worstLanguage.code)?.flag || ''} ${report.globalStats.worstLanguage.rate}%`}
              color="text-red-400"
            />
            <StatCard
              label="Taux moyen"
              value={`${report.globalStats.averageRate}%`}
              color="text-blue-400"
            />
            <StatCard
              label="Requetes analysees"
              value={`${report.globalStats.totalQueriesRun}`}
              subtext={`${report.globalStats.totalCitations} citations`}
              color="text-zinc-300"
            />
          </div>

          {/* Citation Matrix */}
          <LanguageCitationMatrix summaries={report.summaryByLanguage} />

          {/* Opportunities */}
          {report.opportunities.length > 0 && (
            <div>
              <h2 className="text-white font-semibold text-lg mb-4">Opportunites identifiees</h2>
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                {report.opportunities.map((opp, i) => (
                  <LanguageOpportunityCard key={i} opportunity={opp} />
                ))}
              </div>
            </div>
          )}

          {/* Detail accordion */}
          <div>
            <h2 className="text-white font-semibold text-lg mb-4">Detail par requete</h2>
            <div className="space-y-2">
              {report.summaryByLanguage.map(summary => {
                const langInfo = SUPPORTED_LANGUAGES.find(l => l.code === summary.language);
                const isExpanded = expandedLanguage === summary.language;
                const langResults = getResultsByLanguage(summary.language);
                const citedCount = langResults.filter(r => r.cited).length;

                return (
                  <div key={summary.language} className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
                    <button
                      onClick={() => setExpandedLanguage(isExpanded ? null : summary.language)}
                      className="w-full flex items-center justify-between px-5 py-4 hover:bg-white/[0.02] transition-colors cursor-pointer"
                    >
                      <div className="flex items-center gap-3">
                        <span className="text-lg">{langInfo?.flag}</span>
                        <span className="text-[14px] text-white font-medium">{langInfo?.label}</span>
                        <span className="text-[13px] text-zinc-500">
                          ({citedCount}/{langResults.length} citations, {summary.overallRate}%)
                        </span>
                      </div>
                      {isExpanded ? <ChevronUp className="w-4 h-4 text-zinc-500" /> : <ChevronDown className="w-4 h-4 text-zinc-500" />}
                    </button>

                    {isExpanded && (
                      <div className="border-t border-white/[0.04] divide-y divide-white/[0.04]">
                        {/* Group by query */}
                        {groupByQuery(langResults).map(group => (
                          <div key={group.queryId} className="px-5 py-3">
                            <p className="text-[13px] text-zinc-300 font-medium mb-2">
                              &laquo; {group.query} &raquo;
                            </p>
                            <div className="flex flex-wrap gap-3">
                              {group.engines.map(eng => (
                                <div key={eng.engine} className="flex items-center gap-1.5 text-[13px]">
                                  <span className={`font-medium ${
                                    eng.engine === 'chatgpt' ? 'text-emerald-400' :
                                    eng.engine === 'perplexity' ? 'text-blue-400' : 'text-purple-400'
                                  }`}>
                                    {eng.engine}
                                  </span>
                                  {eng.cited ? (
                                    <CheckCircle className="w-3.5 h-3.5 text-emerald-400" />
                                  ) : (
                                    <XCircle className="w-3.5 h-3.5 text-zinc-600" />
                                  )}
                                  <span className="text-zinc-500">
                                    {eng.cited ? `(${eng.position}, ${eng.sentiment})` : 'Non cite'}
                                  </span>
                                </div>
                              ))}
                            </div>
                            {group.competitors.length > 0 && (
                              <p className="text-[12px] text-zinc-600 mt-1">
                                Concurrents cites : {group.competitors.join(', ')}
                              </p>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

// === HELPERS ===

function StatCard({ label, value, subtext, color }: { label: string; value: string; subtext?: string; color: string }) {
  return (
    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
      <div className="text-[11px] uppercase tracking-wider text-zinc-600 font-medium">{label}</div>
      <div className={`text-2xl font-bold mt-1 ${color}`}>{value}</div>
      {subtext && <div className="text-[13px] text-zinc-500 mt-0.5">{subtext}</div>}
    </div>
  );
}

interface QueryGroup {
  queryId: string;
  query: string;
  engines: { engine: string; cited: boolean; position: string; sentiment: string }[];
  competitors: string[];
}

function groupByQuery(results: LanguageCitationResult[]): QueryGroup[] {
  const groups: Record<string, QueryGroup> = {};

  for (const r of results) {
    if (!groups[r.queryId]) {
      groups[r.queryId] = {
        queryId: r.queryId,
        query: r.query,
        engines: [],
        competitors: [],
      };
    }
    groups[r.queryId].engines.push({
      engine: r.engine,
      cited: r.cited,
      position: r.position,
      sentiment: r.sentiment,
    });
    for (const comp of r.competitorsCited) {
      if (!groups[r.queryId].competitors.includes(comp)) {
        groups[r.queryId].competitors.push(comp);
      }
    }
  }

  return Object.values(groups);
}

