// ═══════════════════════════════════════════════════════════
// TYPES
// ═══════════════════════════════════════════════════════════

interface SidebarItem {
  type: 'link';
  id: string;
  label: string;
  icon: React.ElementType;
  badge?: string;
  badgeColor?: string;
}

interface SidebarSeparator {
  type: 'separator';
  label: string;
}

type SidebarEntry = SidebarItem | SidebarSeparator;

// ═══════════════════════════════════════════════════════════
// MAPPING SECTION → SOUS-ITEMS (SOURCE DE VÉRITÉ)
// ═══════════════════════════════════════════════════════════

